  1→// Query protocol — WebSocket wire format for the cloud relay.
  2→// All frame types prefixed with "q:" so they route cleanly in the ws.service dispatcher.
  3→//
  4→// Domain constants (QUERY_RESOURCES, MUTATION_NAMES, SIDECAR_NOTIFY_EVENTS)
  5→// live in shared/events.ts — the single source of truth for all app events
  6→// and resources. This file only defines the wire format that carries them.
  7→
  8→import type { QueryResource, MutationName, CommandName, ProtocolEvent } from "../events";
  9→
 10→// Re-export so existing `import { QueryResource } from "query-protocol"` still works.
 11→export type { QueryResource, MutationName, CommandName, ProtocolEvent };
 12→export { QUERY_RESOURCES, MUTATION_NAMES, COMMAND_NAMES, PROTOCOL_EVENTS, SIDECAR_NOTIFY_EVENTS } from "../events";
 13→export type { SidecarNotifyEvent } from "../events";
 14→
 15→// ---- Client → Server Frames ----
 16→
 17→/** Client requests data (one-shot). */
 18→export interface QRequestFrame {
 19→  type: "q:request";
 20→  id: string;
 21→  resource: QueryResource;
 22→  params?: Record<string, unknown>;
 23→}
 24→
 25→/** Client subscribes to live updates for a resource. */
 26→export interface QSubscribeFrame {
 27→  type: "q:subscribe";
 28→  id: string;
 29→  resource: QueryResource;
 30→  params?: Record<string, unknown>;
 31→}
 32→
 33→/** Client unsubscribes by subscription ID (no resource/params needed). */
 34→export interface QUnsubscribeFrame {
 35→  type: "q:unsubscribe";
 36→  id: string;
 37→}
 38→
 39→/** Client requests a mutation. Field is `action`, not `mutation`. */
 40→export interface QMutateFrame {
 41→  type: "q:mutate";
 42→  id: string;
 43→  action: MutationName;
 44→  params: Record<string, unknown>;
 45→}
 46→
 47→/** Client sends an async command (e.g. sendMessage, stopSession). */
 48→export interface QCommandFrame {
 49→  type: "q:command";
 50→  id: string;
 51→  command: CommandName;
 52→  params: Record<string, unknown>;
 53→}
 54→
 55→/** All frames a client can send. */
 56→export type QClientFrame = QRequestFrame | QSubscribeFrame | QUnsubscribeFrame | QMutateFrame | QCommandFrame;
 57→
 58→// ---- Server → Client Frames ----
 59→
 60→/** Server returns data for a one-shot request. */
 61→export interface QResponseFrame {
 62→  type: "q:response";
 63→  id: string;
 64→  data: unknown;
 65→}
 66→
 67→/** Server pushes a full snapshot to a subscriber (keyed by subscription ID). */
 68→export interface QSnapshotFrame {
 69→  type: "q:snapshot";
 70→  id: string;
 71→  data: unknown;
 72→  cursor?: number;
 73→}
 74→
 75→/** Server pushes incremental update (keyed by subscription ID). */
 76→export interface QDeltaFrame {
 77→  type: "q:delta";
 78→  id: string;
 79→  upserted?: unknown[];
 80→  removed?: string[];
 81→  cursor?: number;
 82→}
 83→
 84→/** Server returns mutation result. Uses `success`, not `ok`. */
 85→export interface QMutateResultFrame {
 86→  type: "q:mutate_result";
 87→  id: string;
 88→  success: boolean;
 89→  data?: unknown;
 90→  error?: string;
 91→}
 92→
 93→/** Server tells clients to refetch stale resources. */
 94→export interface QInvalidateFrame {
 95→  type: "q:invalidate";
 96→  resources: QueryResource[];
 97→}
 98→
 99→/** Server acknowledges an async command. */
100→export interface QCommandAckFrame {
101→  type: "q:command_ack";
102→  id: string;
103→  accepted: boolean;
104→  commandId?: string;
105→  error?: string;
106→}
107→
108→/** Server pushes an ephemeral event (no subscription needed). */
109→export interface QEventFrame {
110→  type: "q:event";
111→  event: string;
112→  data: unknown;
113→}
114→
115→/** Server error for a specific request. */
116→export interface QErrorFrame {
117→  type: "q:error";
118→  id: string;
119→  code: string;
120→  message: string;
121→}
122→
123→/** All frames a server can send. */
124→export type QServerFrame =
125→  | QResponseFrame
126→  | QSnapshotFrame
127→  | QDeltaFrame
128→  | QMutateResultFrame
129→  | QCommandAckFrame
130→  | QEventFrame
131→  | QInvalidateFrame
132→  | QErrorFrame;
133→

