2446→+  onSnapshot: SnapshotCallback,
2447→+  onDelta?: DeltaCallback
2448→+): () => void {
2449→+  const id = nextSubId();
2450→+  const sub: Subscription = { id, resource, params, onSnapshot, onDelta };
2451→+  subscriptions.set(id, sub);
2452→+
2453→+  // If connected, send subscribe frame immediately
2454→+  if (connected && ws) {
2455→+    sendFrame({
2456→+      type: "q:subscribe",
2457→+      id,
2458→+      resource,
2459→+      ...(params ? { params } : {}),
2460→+    });
2461→+  }
2462→+
2463→+  // Return unsubscribe function
2464→+  return () => {
2465→+    subscriptions.delete(id);
