2471→+
2472→+/** Check if the client is currently connected. */
2473→+export function isConnected(): boolean {
2474→+  return connected;
2475→+}
2476→+
2477→+/**
2478→+ * Send an async command via the q:command frame.
2479→+ * Used by upcoming cloud/relay feature -- no desktop consumer yet.
2480→+ * Returns a promise that resolves when the server sends q:command_ack.
2481→+ */
2482→+export function sendCommand(
2483→+  command: CommandName,
2484→+  params: Record<string, unknown>
2485→+): Promise<{ accepted: boolean; commandId?: string; error?: string }> {
2486→+  const id = `cmd_${++commandCounter}`;
2487→+
2488→+  return new Promise((resolve, reject) => {
2489→+    pendingCommands.set(id, { resolve, reject });
2490→+
2491→+    sendFrame({
2492→+      type: "q:command",
2493→+      id,
2494→+      command,
2495→+      params,
2496→+    });
2497→+
2498→+    // Timeout after 30s to prevent leaked promises
2499→+    setTimeout(() => {
2500→+      if (pendingCommands.has(id)) {
2501→+        pendingCommands.delete(id);
2502→+        reject(new Error(`Command ${command} timed out`));
2503→+      }
2504→+    }, 30_000);
2505→+  });
2506→+}
2507→+
2508→+/**
2509→+ * Register a callback for q:event broadcasts.
2510→+ * Used by upcoming cloud/relay feature -- no desktop consumer yet.
2511→+ * Returns an unregister function.
2512→+ */
2513→+export function onEvent(callback: EventCallback): () => void {
2514→+  eventListeners.add(callback);
2515→+  return () => {
2516→+    eventListeners.delete(callback);
2517→+  };
2518→+}
2519→+
2520→+/**
2521→+ * Register a callback for connection state changes.
2522→+ * Fires with `true` when connected, `false` when disconnected.
2523→+ * Used by useQuerySubscription to re-evaluate subscriptions after reconnect.
2524→+ * Returns an unregister function.
2525→+ */
2526→+export function onConnectionChange(callback: (connected: boolean) => void): () => void {
2527→+  connectionChangeListeners.add(callback);
2528→+  return () => {
2529→+    connectionChangeListeners.delete(callback);
2530→+  };
2531→+}
2532→+
2533→+// ---- Internal ----
2534→+
2535→+async function openSocket(): Promise<void> {
2536→+  const port = await getBackendPort();
2537→+  const url = `ws://localhost:${port}/ws`;
2538→+
2539→+  ws = new WebSocket(url);
2540→+
2541→+  ws.onopen = () => {
2542→+    // Localhost connections are auto-authenticated by the backend.
2543→+    // Wait for the "connected" frame in onmessage.
2544→+  };
2545→+
2546→+  ws.onmessage = (evt) => {
2547→+    let msg: Record<string, unknown>;
2548→+    try {
2549→+      msg = JSON.parse(evt.data as string);
2550→+    } catch {
2551→+      return;
2552→+    }
2553→+
2554→+    const type = typeof msg.type === "string" ? msg.type : "";
2555→+
2556→+    match(type)
2557→+      .with("connected", () => {
2558→+        _connectionId = msg.connectionId as string;
2559→+        connected = true;
2560→+        connecting = false;
2561→+        reconnectAttempt = 0;
2562→+
2563→+        // Re-subscribe all active subscriptions (reconnect scenario)
2564→+        resubscribeAll();
2565→+
2566→+        // Notify hooks that connection is available so they can set up subscriptions
2567→+        notifyConnectionChange(true);
2568→+
2569→+        connectResolve?.();
2570→+        connectResolve = null;
2571→+        connectReject = null;
2572→+      })
2573→+      .with("ping", () => {
2574→+        sendFrame({ type: "pong" });
2575→+      })
2576→+      .with("q:snapshot", () => {
2577→+        const sub = subscriptions.get(msg.id as string);
2578→+        sub?.onSnapshot(msg.data);
2579→+      })
2580→+      .with("q:delta", () => {
2581→+        const sub = subscriptions.get(msg.id as string);
2582→+        sub?.onDelta?.(
2583→+          msg.upserted as unknown[] | undefined,
2584→+          msg.removed as string[] | undefined,
2585→+          msg.cursor as number | undefined
2586→+        );
2587→+      })
2588→+      .with("q:command_ack", () => {
2589→+        const pending = pendingCommands.get(msg.id as string);
2590→+        if (pending) {
2591→+          pendingCommands.delete(msg.id as string);
2592→+          pending.resolve({
2593→+            accepted: msg.accepted as boolean,
2594→+            commandId: msg.commandId as string | undefined,
2595→+            error: msg.error as string | undefined,
2596→+          });
2597→+        }
2598→+      })
2599→+      .with("q:event", () => {
2600→+        const event = msg.event as string;
2601→+        const data = msg.data;
2602→+        for (const cb of eventListeners) {
2603→+          try {
2604→+            cb(event, data);
2605→+          } catch (err) {
2606→+            console.error("[WS] Event listener error:", err);
2607→+          }
2608→+        }
2609→+      })
2610→+      .with("q:error", () => {
2611→+        console.warn("[WS] Query error:", msg.message, "for sub:", msg.id);
2612→+      })
2613→+      .otherwise(() => {
2614→+        // Ignore unknown frame types (q:response, q:mutate_result, etc.)
2615→+      });
2616→+  };
2617→+
2618→+  ws.onerror = () => {
2619→+    // onerror fires before onclose — actual cleanup happens in onclose
2620→+  };
2621→+
2622→+  ws.onclose = () => {
2623→+    const wasConnected = connected;
2624→+    connected = false;
2625→+    _connectionId = null;
2626→+    ws = null;
2627→+
2628→+    // Reject all pending commands immediately — they can't succeed without a connection
2629→+    for (const [_id, pending] of pendingCommands) {
2630→+      pending.reject(new Error("WebSocket disconnected"));
2631→+    }
2632→+    pendingCommands.clear();
2633→+
2634→+    if (connecting) {
2635→+      // Initial connection failed — reject the connect() promise
2636→+      connecting = false;
2637→+      connectReject?.(new Error("WebSocket connection failed"));
2638→+      connectResolve = null;
2639→+      connectReject = null;
2640→+    }
2641→+
2642→+    if (wasConnected) {
2643→+      notifyConnectionChange(false);
2644→+    }
2645→+
2646→+    // Only auto-reconnect if we had previously connected or have active subscriptions
2647→+    if (wasConnected || subscriptions.size > 0) {
2648→+      scheduleReconnect();
2649→+    }
2650→+  };
2651→+}
2652→+
2653→+/** Notify all connection change listeners. */
2654→+function notifyConnectionChange(state: boolean): void {
2655→+  for (const cb of connectionChangeListeners) {
2656→+    try {
2657→+      cb(state);
2658→+    } catch (err) {
2659→+      console.error("[WS] Connection change listener error:", err);
2660→+    }
2661→+  }
2662→+}
2663→+
2664→+function sendFrame(frame: Record<string, unknown>): void {
2665→+  if (ws && ws.readyState === WebSocket.OPEN) {
2666→+    try {
2667→+      ws.send(JSON.stringify(frame));
2668→+    } catch {
2669→+      // Connection may have closed between readyState check and send
2670→+    }
2671→+  }
2672→+}
2673→+
2674→+/** Re-subscribe all active subscriptions after reconnect. */
2675→+function resubscribeAll(): void {
2676→+  for (const sub of subscriptions.values()) {
2677→+    sendFrame({
2678→+      type: "q:subscribe",
2679→+      id: sub.id,
2680→+      resource: sub.resource,
2681→+      ...(sub.params ? { params: sub.params } : {}),
2682→+    });
2683→+  }
2684→+}
2685→+
2686→+/** Schedule a reconnection with exponential backoff. */
2687→+function scheduleReconnect(): void {
2688→+  if (reconnectTimer) return;
2689→+
2690→+  const delay = Math.min(BACKOFF_BASE_MS * Math.pow(2, reconnectAttempt), BACKOFF_MAX_MS);
2691→+  reconnectAttempt++;
2692→+
2693→+  if (import.meta.env.DEV) {
2694→+    console.log(`[WS] Reconnecting in ${delay}ms (attempt ${reconnectAttempt})`);
2695→+  }
2696→+
2697→+  reconnectTimer = setTimeout(() => {
2698→+    reconnectTimer = null;
2699→+    connecting = true;
2700→+
2701→+    // Set up resolve/reject so subscriptions get re-established
2702→+    connectResolve = null;
2703→+    connectReject = null;
2704→+
2705→+    openSocket().catch(() => {
2706→+      connecting = false;
2707→+      // onclose handler will schedule another reconnect
2708→+    });
2709→+  }, delay);
2710→+}
