2730→+/**
2731→+ * Connects the WebSocket query protocol client on app mount.
2732→+ *
2733→+ * All reactive data delivery happens through q:snapshot and q:delta pushed
2734→+ * to active WS subscriptions — no separate invalidation bridge is needed.
2735→+ */
2736→+
2737→+import { useEffect } from "react";
2738→+import { connect } from "@/platform/ws";
2739→+
2740→+export function useQueryProtocol(): void {
2741→+  // Connect the WS client once on mount
2742→+  useEffect(() => {
2743→+    connect().catch((err) => {
2744→+      // Non-fatal: WS is additive. HTTP + Tauri events still work.
2745→+      if (import.meta.env.DEV) {
2746→+        console.warn("[QueryProtocol] WS connection failed:", err);
2747→+      }
2748→+    });
