2751→diff --git a/src/shared/hooks/useQuerySubscription.ts b/src/shared/hooks/useQuerySubscription.ts
2752→new file mode 100644
2753→index 000000000..17da2791b
2754→--- /dev/null
2755→+++ b/src/shared/hooks/useQuerySubscription.ts
2756→@@ -0,0 +1,145 @@
2757→+/**
2758→+ * Hook that subscribes to a query protocol resource via WebSocket and writes
2759→+ * snapshots/deltas directly into the React Query cache.
2760→+ *
2761→+ * This bypasses the HTTP refetch cycle: instead of
2762→+ *   Tauri event -> invalidate -> HTTP GET -> render
2763→+ * it becomes:
2764→+ *   WS q:snapshot -> setQueryData -> render
2765→+ *
2766→+ * The HTTP queryFn remains as fallback for initial load (before WS connects)
2767→+ * and for non-Tauri environments.
2768→+ */
2769→+
2770→+import { useEffect, useMemo, useRef, useState } from "react";
2771→+import { useQueryClient, type QueryKey } from "@tanstack/react-query";
2772→+import { subscribe, isConnected, onConnectionChange } from "@/platform/ws";
2773→+import type { QueryResource } from "@shared/types/query-protocol";
2774→+
2775→+interface UseQuerySubscriptionOptions {
2776→+  /** React Query cache key to write data into. */
2777→+  queryKey: QueryKey;
2778→+  /** Optional params passed to the backend query (e.g., { state: "ready,initializing" }). */
2779→+  params?: Record<string, unknown>;
2780→+  /** Disable the subscription (e.g., when data isn't needed). Defaults to true. */
2781→+  enabled?: boolean;
2782→+  /** Custom delta merge. Receives old cache value + delta items, returns new cache value.
2783→+   *  When provided, replaces the default flat-array merge for q:delta frames. */
2784→+  mergeDelta?: (old: unknown, upserted?: unknown[], removed?: string[]) => unknown;
2785→+}
2786→+
2787→+/**
2788→+ * Subscribe to a query protocol resource and write snapshots/deltas
2789→+ * directly into the React Query cache.
2790→+ *
2791→+ * On q:snapshot: replaces the entire cache entry via setQueryData.
2792→+ * On q:delta: merges upserted items and removes removed items (for list resources).
2793→+ *
2794→+ * IMPORTANT: queryKey must be a pure function of (resource, params). The queryKey
2795→+ * is stored in a ref and not included in the subscription effect's dependency
2796→+ * array — if queryKey drifts independently from params, the snapshot would write
2797→+ * to the wrong cache entry.
2798→+ */
2799→+export function useQuerySubscription(
2800→+  resource: QueryResource,
2801→+  options: UseQuerySubscriptionOptions
2802→+): void {
2803→+  const { queryKey, params, enabled = true, mergeDelta } = options;
2804→+  const queryClient = useQueryClient();
2805→+
2806→+  // Track WS connection state so the subscription effect re-runs when
2807→+  // the connection comes up. Without this, hooks that mount before WS
2808→+  // connects would return early and never subscribe (staleTime: Infinity
2809→+  // means the HTTP fallback data would never refresh).
2810→+  const [wsConnected, setWsConnected] = useState(isConnected());
2811→+  useEffect(() => {
2812→+    return onConnectionChange(setWsConnected);
2813→+  }, []);
2814→+
2815→+  // Stable string key for params so effect doesn't re-run on referential changes
2816→+  const stableParamsKey = useMemo(
2817→+    () => (params ? JSON.stringify(params) : ""),
2818→+    [params]
2819→+  );
2820→+
2821→+  // Use refs for callbacks to avoid re-subscribing on every render
2822→+  const queryClientRef = useRef(queryClient);
2823→+  queryClientRef.current = queryClient;
2824→+
2825→+  const queryKeyRef = useRef(queryKey);
2826→+  queryKeyRef.current = queryKey;
2827→+
2828→+  const mergeDeltaRef = useRef(mergeDelta);
2829→+  mergeDeltaRef.current = mergeDelta;
2830→+
2831→+  useEffect(() => {
2832→+    if (!enabled || !wsConnected) return;
2833→+
2834→+    const unsubscribe = subscribe(
2835→+      resource,
2836→+      params,
2837→+      // onSnapshot: replace entire cache entry
2838→+      (data) => {
2839→+        queryClientRef.current.setQueryData(queryKeyRef.current, data);
2840→+      },
2841→+      // onDelta: merge incremental updates (for list resources like messages)
2842→+      (upserted, removed) => {
2843→+        if (!upserted && !removed) return;
2844→+
2845→+        queryClientRef.current.setQueryData(queryKeyRef.current, (old: unknown) => {
2846→+          // Custom merge strategy (e.g., PaginatedMessages for message cache)
2847→+          if (mergeDeltaRef.current) {
2848→+            return mergeDeltaRef.current(old, upserted, removed);
2849→+          }
2850→+
2851→+          // Default: flat array merge
2852→+          if (!Array.isArray(old)) return old;
2853→+
2854→+          let result = [...old];
2855→+
2856→+          // Remove items by ID
2857→+          if (removed && removed.length > 0) {
2858→+            const removeSet = new Set(removed);
2859→+            result = result.filter(
2860→+              (item: unknown) =>
2861→+                !(
2862→+                  typeof item === "object" &&
2863→+                  item !== null &&
2864→+                  "id" in item &&
2865→+                  removeSet.has((item as { id: string }).id)
2866→+                )
2867→+            );
2868→+          }
2869→+
2870→+          // Upsert items (update existing or append new)
2871→+          if (upserted && upserted.length > 0) {
2872→+            for (const item of upserted) {
2873→+              if (typeof item !== "object" || item === null || !("id" in item)) {
2874→+                result.push(item);
2875→+                continue;
2876→+              }
2877→+              const itemId = (item as { id: string }).id;
2878→+              const idx = result.findIndex(
2879→+                (existing: unknown) =>
2880→+                  typeof existing === "object" &&
2881→+                  existing !== null &&
2882→+                  "id" in existing &&
2883→+                  (existing as { id: string }).id === itemId
2884→+              );
2885→+              if (idx >= 0) {
2886→+                result[idx] = item;
2887→+              } else {
2888→+                result.push(item);
2889→+              }
2890→+            }
2891→+          }
2892→+
2893→+          return result;
2894→+        });
2895→+      }
2896→+    );
2897→+
2898→+    return unsubscribe;
2899→+    // eslint-disable-next-line react-hooks/exhaustive-deps
2900→+  }, [resource, enabled, stableParamsKey, wsConnected]);
2901→+}
