 3→/**
 4→ * Create an optimistic (placeholder) Workspace object for instant UI feedback
 5→ * while the backend creates the real workspace asynchronously.
 6→ *
 7→ * Used in:
 8→ * - useRepoActions.createAndSelectWorkspace() (quick "+" button flow)
 9→ * - useRepoActions.handleOpenProject() (native folder dialog flow)
10→ * - useRepoActions.handleCloneRepository() (git clone flow)
11→ * - useCreateWorkspace() onMutate (React Query optimistic update)
12→ */
13→export function createOptimisticWorkspace(repoId: string, repoName: string): Workspace {
14→  return {
15→    id: `optimistic-${Date.now()}`,
16→    repository_id: repoId,
17→    slug: "",
18→    title: null,
19→    git_branch: null,
20→    git_target_branch: null,
21→    state: "initializing",
22→    current_session_id: null,
23→    session_status: null,
24→    model: null,
25→    session_error_category: null,
26→    session_error_message: null,
27→    latest_message_sent_at: null,
28→    init_stage: null,
29→    setup_status: "none",
30→    error_message: null,
31→    updated_at: new Date().toISOString(),
32→    repo_name: repoName,
33→    root_path: "",
34→    workspace_path: "",
35→  };
36→}
37→
38→/**
39→ * Merge a workspace delta (q:delta) into the existing RepoGroup[] cache.
40→ * Replaces matching workspaces by ID within their repo group, or appends if new.
41→ * Used by useQuerySubscription's mergeDelta option.
42→ */
43→export function mergeWorkspaceDelta(
44→  old: unknown,
45→  upserted?: unknown[],
46→  removed?: string[]
47→): unknown {
48→  if (!Array.isArray(old)) return old;
49→  const groups = old as RepoGroup[];
50→  if (!upserted && !removed) return old;
51→
52→  let result = groups.map(g => ({ ...g, workspaces: [...g.workspaces] }));
53→
54→  if (removed?.length) {
55→    const removeSet = new Set(removed);
56→    result = result.map(g => ({
57→      ...g,
58→      workspaces: g.workspaces.filter(w => !removeSet.has(w.id)),
59→    }));
60→  }
61→
62→  if (upserted?.length) {
63→    for (const item of upserted) {
64→      const ws = item as Workspace;
65→      const group = result.find(g => g.repo_id === ws.repository_id);
66→      if (!group) continue;
67→      const idx = group.workspaces.findIndex(w => w.id === ws.id);
68→      if (idx >= 0) {
69→        group.workspaces[idx] = ws;
70→      } else {
71→        group.workspaces.push(ws);
72→      }
73→    }
74→  }
75→
76→  return result;
77→}
