2436→+/**
2437→+ * WebSocket Query Protocol Client
2438→+ *
2439→+ * Singleton client that connects to the backend's /ws endpoint and handles
2440→+ * the q:* protocol for real-time data subscriptions. Used by the desktop
2441→+ * frontend to receive data pushes instead of HTTP polling.
2442→+ *
2443→+ * Protocol:
2444→+ *   Client sends: q:subscribe, q:unsubscribe
2445→+ *   Server sends: q:snapshot, q:delta, q:error, ping
2446→+ *   Client responds to ping with pong
2447→+ *
2448→+ * On reconnect, all active subscriptions are re-established automatically.
2449→+ */
2450→+
2451→+import { match } from "ts-pattern";
2452→+import { getBackendPort } from "@/shared/config/api.config";
2453→+import type { QueryResource, CommandName } from "@shared/types/query-protocol";
2454→+
2455→+// ---- Types ----
2456→+
2457→+type SnapshotCallback = (data: unknown) => void;
2458→+type DeltaCallback = (upserted?: unknown[], removed?: string[], cursor?: number) => void;
2459→+type EventCallback = (event: string, data: unknown) => void;
2460→+
2461→+interface PendingCommand {
2462→+  resolve: (result: { accepted: boolean; commandId?: string; error?: string }) => void;
2463→+  reject: (err: Error) => void;
2464→+}
2465→+
2466→+interface Subscription {
2467→+  id: string;
2468→+  resource: QueryResource;
2469→+  params?: Record<string, unknown>;
2470→+  onSnapshot: SnapshotCallback;
2471→+  onDelta?: DeltaCallback;
2472→+}
2473→+
2474→+// ---- Reconnect Config ----
2475→+
2476→+const BACKOFF_BASE_MS = 500;
2477→+const BACKOFF_MAX_MS = 8000;
2478→+
2479→+// ---- Singleton State ----
2480→+
2481→+let ws: WebSocket | null = null;
2482→+let _connectionId: string | null = null;
2483→+let connected = false;
2484→+let connecting = false;
2485→+let reconnectAttempt = 0;
2486→+let reconnectTimer: ReturnType<typeof setTimeout> | null = null;
2487→+let subCounter = 0;
2488→+
2489→+/** Active subscriptions keyed by client-assigned ID. */
2490→+const subscriptions = new Map<string, Subscription>();
2491→+
2492→+/** Pending commands waiting for q:command_ack. */
2493→+const pendingCommands = new Map<string, PendingCommand>();
2494→+
2495→+/** Listeners for q:event broadcasts. */
2496→+const eventListeners = new Set<EventCallback>();
2497→+
2498→+/** Listeners notified when connection state changes (connected/disconnected). */
2499→+const connectionChangeListeners = new Set<(connected: boolean) => void>();
2500→+
2501→+/** Counter for generating unique command frame IDs. */
2502→+let commandCounter = 0;
2503→+
2504→+/** Resolvers waiting for the initial "connected" frame after open. */
2505→+let connectResolve: (() => void) | null = null;
2506→+let connectReject: ((err: Error) => void) | null = null;
2507→+
2508→+// ---- Public API ----
2509→+
2510→+/** Generate a unique subscription ID. */
2511→+function nextSubId(): string {
2512→+  return `sub_${++subCounter}`;
2513→+}
2514→+
2515→+/**
2516→+ * Connect to the backend WebSocket. Resolves once authenticated.
2517→+ * No-op if already connected or connecting.
2518→+ */
2519→+export async function connect(): Promise<void> {
2520→+  if (connected) return;
2521→+  if (connecting) {
2522→+    // Wait for the in-flight connection attempt
2523→+    return new Promise<void>((resolve, reject) => {
2524→+      const prevResolve = connectResolve;
2525→+      const prevReject = connectReject;
2526→+      connectResolve = () => {
2527→+        prevResolve?.();
2528→+        resolve();
2529→+      };
2530→+      connectReject = (err) => {
2531→+        prevReject?.(err);
2532→+        reject(err);
2533→+      };
2534→+    });
2535→+  }
2536→+
2537→+  connecting = true;
2538→+
2539→+  return new Promise<void>((resolve, reject) => {
2540→+    connectResolve = resolve;
2541→+    connectReject = reject;
2542→+    openSocket().catch((err) => {
2543→+      connecting = false;
2544→+      connectReject?.(err);
2545→+      connectResolve = null;
2546→+      connectReject = null;
2547→+    });
2548→+  });
2549→+}
2550→+
2551→+/**
2552→+ * Subscribe to a query resource. Returns an unsubscribe function.
2553→+ *
2554→+ * On subscription, the server sends an initial q:snapshot. Subsequent
2555→+ * invalidations push q:snapshot (full replace) or q:delta (incremental).
2556→+ */
2557→+export function subscribe(
2558→+  resource: QueryResource,
2559→+  params: Record<string, unknown> | undefined,
2560→+  onSnapshot: SnapshotCallback,
2561→+  onDelta?: DeltaCallback
