2563→+  const id = nextSubId();
2564→+  const sub: Subscription = { id, resource, params, onSnapshot, onDelta };
2565→+  subscriptions.set(id, sub);
2566→+
2567→+  // If connected, send subscribe frame immediately
2568→+  if (connected && ws) {
2569→+    sendFrame({
2570→+      type: "q:subscribe",
2571→+      id,
2572→+      resource,
2573→+      ...(params ? { params } : {}),
2574→+    });
2575→+  }
2576→+
2577→+  // Return unsubscribe function
2578→+  return () => {
2579→+    subscriptions.delete(id);
2580→+    if (connected && ws) {
2581→+      sendFrame({ type: "q:unsubscribe", id });
2582→+    }
2583→+  };
2584→+}
