2593→+ * Used by upcoming cloud/relay feature -- no desktop consumer yet.
2594→+ * Returns a promise that resolves when the server sends q:command_ack.
2595→+ */
2596→+export function sendCommand(
2597→+  command: CommandName,
2598→+  params: Record<string, unknown>
2599→+): Promise<{ accepted: boolean; commandId?: string; error?: string }> {
2600→+  const id = `cmd_${++commandCounter}`;
2601→+
2602→+  return new Promise((resolve, reject) => {
2603→+    pendingCommands.set(id, { resolve, reject });
2604→+
2605→+    sendFrame({
2606→+      type: "q:command",
2607→+      id,
2608→+      command,
2609→+      params,
2610→+    });
2611→+
2612→+    // Timeout after 30s to prevent leaked promises
2613→+    setTimeout(() => {
2614→+      if (pendingCommands.has(id)) {
2615→+        pendingCommands.delete(id);
2616→+        reject(new Error(`Command ${command} timed out`));
2617→+      }
2618→+    }, 30_000);
2619→+  });
2620→+}
2621→+
2622→+/**
2623→+ * Register a callback for q:event broadcasts.
2624→+ * Used by upcoming cloud/relay feature -- no desktop consumer yet.
2625→+ * Returns an unregister function.
2626→+ */
2627→+export function onEvent(callback: EventCallback): () => void {
2628→+  eventListeners.add(callback);
2629→+  return () => {
2630→+    eventListeners.delete(callback);
2631→+  };
2632→+}
2633→+
2634→+/**
2635→+ * Register a callback for connection state changes.
2636→+ * Fires with `true` when connected, `false` when disconnected.
2637→+ * Used by useQuerySubscription to re-evaluate subscriptions after reconnect.
2638→+ * Returns an unregister function.
2639→+ */
2640→+export function onConnectionChange(callback: (connected: boolean) => void): () => void {
2641→+  connectionChangeListeners.add(callback);
2642→+  return () => {
2643→+    connectionChangeListeners.delete(callback);
2644→+  };
2645→+}
2646→+
2647→+// ---- Internal ----
2648→+
2649→+async function openSocket(): Promise<void> {
2650→+  const port = await getBackendPort();
2651→+  const url = `ws://localhost:${port}/ws`;
2652→+
2653→+  ws = new WebSocket(url);
2654→+
2655→+  ws.onopen = () => {
2656→+    // Localhost connections are auto-authenticated by the backend.
2657→+    // Wait for the "connected" frame in onmessage.
2658→+  };
2659→+
2660→+  ws.onmessage = (evt) => {
2661→+    let msg: Record<string, unknown>;
2662→+    try {
2663→+      msg = JSON.parse(evt.data as string);
2664→+    } catch {
2665→+      return;
2666→+    }
2667→+
2668→+    const type = typeof msg.type === "string" ? msg.type : "";
2669→+
2670→+    match(type)
2671→+      .with("connected", () => {
2672→+        _connectionId = msg.connectionId as string;
2673→+        connected = true;
2674→+        connecting = false;
2675→+        reconnectAttempt = 0;
2676→+
2677→+        // Re-subscribe all active subscriptions (reconnect scenario)
2678→+        resubscribeAll();
2679→+
2680→+        // Notify hooks that connection is available so they can set up subscriptions
2681→+        notifyConnectionChange(true);
2682→+
2683→+        connectResolve?.();
2684→+        connectResolve = null;
2685→+        connectReject = null;
2686→+      })
2687→+      .with("ping", () => {
2688→+        sendFrame({ type: "pong" });
2689→+      })
2690→+      .with("q:snapshot", () => {
2691→+        const sub = subscriptions.get(msg.id as string);
2692→+        sub?.onSnapshot(msg.data);
2693→+      })
2694→+      .with("q:delta", () => {
2695→+        const sub = subscriptions.get(msg.id as string);
2696→+        sub?.onDelta?.(
2697→+          msg.upserted as unknown[] | undefined,
2698→+          msg.removed as string[] | undefined,
2699→+          msg.cursor as number | undefined
2700→+        );
2701→+      })
2702→+      .with("q:command_ack", () => {
2703→+        const pending = pendingCommands.get(msg.id as string);
2704→+        if (pending) {
2705→+          pendingCommands.delete(msg.id as string);
2706→+          pending.resolve({
2707→+            accepted: msg.accepted as boolean,
2708→+            commandId: msg.commandId as string | undefined,
2709→+            error: msg.error as string | undefined,
2710→+          });
2711→+        }
2712→+      })
2713→+      .with("q:event", () => {
2714→+        const event = msg.event as string;
2715→+        const data = msg.data;
2716→+        for (const cb of eventListeners) {
2717→+          try {
2718→+            cb(event, data);
2719→+          } catch (err) {
2720→+            console.error("[WS] Event listener error:", err);
2721→+          }
2722→+        }
2723→+      })
2724→+      .with("q:error", () => {
2725→+        console.warn("[WS] Query error:", msg.message, "for sub:", msg.id);
2726→+      })
2727→+      .otherwise(() => {
2728→+        // Ignore unknown frame types (q:response, q:mutate_result, etc.)
2729→+      });
2730→+  };
2731→+
2732→+  ws.onerror = () => {
2733→+    // onerror fires before onclose — actual cleanup happens in onclose
2734→+  };
2735→+
2736→+  ws.onclose = () => {
2737→+    const wasConnected = connected;
2738→+    connected = false;
2739→+    _connectionId = null;
2740→+    ws = null;
2741→+
2742→+    // Reject all pending commands immediately — they can't succeed without a connection
2743→+    for (const [_id, pending] of pendingCommands) {
2744→+      pending.reject(new Error("WebSocket disconnected"));
2745→+    }
2746→+    pendingCommands.clear();
2747→+
2748→+    if (connecting) {
2749→+      // Initial connection failed — reject the connect() promise
2750→+      connecting = false;
2751→+      connectReject?.(new Error("WebSocket connection failed"));
2752→+      connectResolve = null;
2753→+      connectReject = null;
2754→+    }
2755→+
2756→+    if (wasConnected) {
2757→+      notifyConnectionChange(false);
2758→+    }
2759→+
2760→+    // Only auto-reconnect if we had previously connected or have active subscriptions
2761→+    if (wasConnected || subscriptions.size > 0) {
2762→+      scheduleReconnect();
2763→+    }
2764→+  };
2765→+}
2766→+
2767→+/** Notify all connection change listeners. */
2768→+function notifyConnectionChange(state: boolean): void {
2769→+  for (const cb of connectionChangeListeners) {
2770→+    try {
2771→+      cb(state);
2772→+    } catch (err) {
2773→+      console.error("[WS] Connection change listener error:", err);
2774→+    }
2775→+  }
2776→+}
2777→+
2778→+function sendFrame(frame: Record<string, unknown>): void {
2779→+  if (ws && ws.readyState === WebSocket.OPEN) {
2780→+    try {
2781→+      ws.send(JSON.stringify(frame));
2782→+    } catch {
2783→+      // Connection may have closed between readyState check and send
2784→+    }
2785→+  }
2786→+}
2787→+
2788→+/** Re-subscribe all active subscriptions after reconnect. */
2789→+function resubscribeAll(): void {
2790→+  for (const sub of subscriptions.values()) {
2791→+    sendFrame({
2792→+      type: "q:subscribe",
2793→+      id: sub.id,
2794→+      resource: sub.resource,
2795→+      ...(sub.params ? { params: sub.params } : {}),
2796→+    });
2797→+  }
2798→+}
2799→+
2800→+/** Schedule a reconnection with exponential backoff. */
2801→+function scheduleReconnect(): void {
2802→+  if (reconnectTimer) return;
2803→+
2804→+  const delay = Math.min(BACKOFF_BASE_MS * Math.pow(2, reconnectAttempt), BACKOFF_MAX_MS);
2805→+  reconnectAttempt++;
2806→+
2807→+  if (import.meta.env.DEV) {
2808→+    console.log(`[WS] Reconnecting in ${delay}ms (attempt ${reconnectAttempt})`);
2809→+  }
2810→+
2811→+  reconnectTimer = setTimeout(() => {
2812→+    reconnectTimer = null;
2813→+    connecting = true;
2814→+
2815→+    // Set up resolve/reject so subscriptions get re-established
2816→+    connectResolve = null;
2817→+    connectReject = null;
2818→+
2819→+    openSocket().catch(() => {
2820→+      connecting = false;
2821→+      // onclose handler will schedule another reconnect
2822→+    });
2823→+  }, delay);
2824→+}
