2870→@@ -0,0 +1,142 @@
2871→+/**
2872→+ * Hook that subscribes to a query protocol resource via WebSocket and writes
2873→+ * snapshots/deltas directly into the React Query cache.
2874→+ *
2875→+ * This bypasses the HTTP refetch cycle: instead of
2876→+ *   Tauri event -> invalidate -> HTTP GET -> render
2877→+ * it becomes:
2878→+ *   WS q:snapshot -> setQueryData -> render
2879→+ *
2880→+ * The HTTP queryFn remains as fallback for initial load (before WS connects)
2881→+ * and for non-Tauri environments.
2882→+ */
2883→+
2884→+import { useEffect, useMemo, useRef, useState } from "react";
2885→+import { useQueryClient, type QueryKey } from "@tanstack/react-query";
2886→+import { subscribe, isConnected, onConnectionChange } from "@/platform/ws";
2887→+import type { QueryResource } from "@shared/types/query-protocol";
2888→+
2889→+interface UseQuerySubscriptionOptions {
2890→+  /** React Query cache key to write data into. */
2891→+  queryKey: QueryKey;
2892→+  /** Optional params passed to the backend query (e.g., { state: "ready,initializing" }). */
2893→+  params?: Record<string, unknown>;
2894→+  /** Disable the subscription (e.g., when data isn't needed). Defaults to true. */
2895→+  enabled?: boolean;
2896→+  /** Custom delta merge. Receives old cache value + delta items, returns new cache value.
2897→+   *  When provided, replaces the default flat-array merge for q:delta frames. */
2898→+  mergeDelta?: (old: unknown, upserted?: unknown[], removed?: string[]) => unknown;
2899→+}
2900→+
2901→+/**
2902→+ * Subscribe to a query protocol resource and write snapshots/deltas
2903→+ * directly into the React Query cache.
2904→+ *
2905→+ * On q:snapshot: replaces the entire cache entry via setQueryData.
2906→+ * On q:delta: merges upserted items and removes removed items (for list resources).
2907→+ *
2908→+ * IMPORTANT: queryKey must be a pure function of (resource, params). The queryKey
2909→+ * is stored in a ref and not included in the subscription effect's dependency
2910→+ * array — if queryKey drifts independently from params, the snapshot would write
2911→+ * to the wrong cache entry.
2912→+ */
2913→+export function useQuerySubscription(
2914→+  resource: QueryResource,
2915→+  options: UseQuerySubscriptionOptions
2916→+): void {
2917→+  const { queryKey, params, enabled = true, mergeDelta } = options;
2918→+  const queryClient = useQueryClient();
2919→+
2920→+  // Track WS connection state so the subscription effect re-runs when
2921→+  // the connection comes up. Without this, hooks that mount before WS
2922→+  // connects would return early and never subscribe (staleTime: Infinity
2923→+  // means the HTTP fallback data would never refresh).
2924→+  const [wsConnected, setWsConnected] = useState(isConnected());
2925→+  useEffect(() => {
2926→+    return onConnectionChange(setWsConnected);
2927→+  }, []);
2928→+
2929→+  // Stable string key for params so effect doesn't re-run on referential changes
2930→+  const stableParamsKey = useMemo(() => (params ? JSON.stringify(params) : ""), [params]);
2931→+
2932→+  // Use refs for callbacks to avoid re-subscribing on every render
2933→+  const queryClientRef = useRef(queryClient);
2934→+  queryClientRef.current = queryClient;
2935→+
2936→+  const queryKeyRef = useRef(queryKey);
2937→+  queryKeyRef.current = queryKey;
2938→+
2939→+  const mergeDeltaRef = useRef(mergeDelta);
2940→+  mergeDeltaRef.current = mergeDelta;
2941→+
2942→+  useEffect(() => {
2943→+    if (!enabled || !wsConnected) return;
2944→+
2945→+    const unsubscribe = subscribe(
2946→+      resource,
2947→+      params,
2948→+      // onSnapshot: replace entire cache entry
2949→+      (data) => {
2950→+        queryClientRef.current.setQueryData(queryKeyRef.current, data);
2951→+      },
2952→+      // onDelta: merge incremental updates (for list resources like messages)
2953→+      (upserted, removed) => {
2954→+        if (!upserted && !removed) return;
2955→+
2956→+        queryClientRef.current.setQueryData(queryKeyRef.current, (old: unknown) => {
2957→+          // Custom merge strategy (e.g., PaginatedMessages for message cache)
2958→+          if (mergeDeltaRef.current) {
2959→+            return mergeDeltaRef.current(old, upserted, removed);
2960→+          }
2961→+
2962→+          // Default: flat array merge
2963→+          if (!Array.isArray(old)) return old;
2964→+
2965→+          let result = [...old];
2966→+
2967→+          // Remove items by ID
2968→+          if (removed && removed.length > 0) {
2969→+            const removeSet = new Set(removed);
2970→+            result = result.filter(
2971→+              (item: unknown) =>
2972→+                !(
2973→+                  typeof item === "object" &&
2974→+                  item !== null &&
2975→+                  "id" in item &&
2976→+                  removeSet.has((item as { id: string }).id)
2977→+                )
2978→+            );
2979→+          }
2980→+
2981→+          // Upsert items (update existing or append new)
2982→+          if (upserted && upserted.length > 0) {
2983→+            for (const item of upserted) {
2984→+              if (typeof item !== "object" || item === null || !("id" in item)) {
2985→+                result.push(item);
2986→+                continue;
2987→+              }
2988→+              const itemId = (item as { id: string }).id;
2989→+              const idx = result.findIndex(
2990→+                (existing: unknown) =>
2991→+                  typeof existing === "object" &&
2992→+                  existing !== null &&
2993→+                  "id" in existing &&
2994→+                  (existing as { id: string }).id === itemId
2995→+              );
2996→+              if (idx >= 0) {
2997→+                result[idx] = item;
2998→+              } else {
2999→+                result.push(item);
3000→+              }
3001→+            }
3002→+          }
3003→+
3004→+          return result;
3005→+        });
3006→+      }
3007→+    );
3008→+
3009→+    return unsubscribe;
3010→+    // eslint-disable-next-line react-hooks/exhaustive-deps
3011→+  }, [resource, enabled, stableParamsKey, wsConnected]);
3012→+}
