  1→/**
  2→ * WebSocket Query Protocol Client
  3→ *
  4→ * Singleton client that connects to the backend's /ws endpoint and handles
  5→ * the q:* protocol for real-time data subscriptions. Used by the desktop
  6→ * frontend to receive data pushes instead of HTTP polling.
  7→ *
  8→ * Protocol:
  9→ *   Client sends: q:subscribe, q:unsubscribe
 10→ *   Server sends: q:snapshot, q:delta, q:error, ping
 11→ *   Client responds to ping with pong
 12→ *
 13→ * On reconnect, all active subscriptions are re-established automatically.
 14→ */
 15→
 16→import { match } from "ts-pattern";
 17→import { getBackendPort } from "@/shared/config/api.config";
 18→import type { QueryResource, CommandName } from "@shared/types/query-protocol";
 19→
 20→// ---- Types ----
 21→
 22→type SnapshotCallback = (data: unknown) => void;
 23→type DeltaCallback = (upserted?: unknown[], removed?: string[], cursor?: number) => void;
 24→type EventCallback = (event: string, data: unknown) => void;
 25→
 26→interface PendingCommand {
 27→  resolve: (result: { accepted: boolean; commandId?: string; error?: string }) => void;
 28→  reject: (err: Error) => void;
 29→}
 30→
 31→interface Subscription {
 32→  id: string;
 33→  resource: QueryResource;
 34→  params?: Record<string, unknown>;
 35→  onSnapshot: SnapshotCallback;
 36→  onDelta?: DeltaCallback;
 37→}
 38→
 39→// ---- Reconnect Config ----
 40→
 41→const BACKOFF_BASE_MS = 500;
 42→const BACKOFF_MAX_MS = 8000;
 43→
 44→// ---- Singleton State ----
 45→
 46→let ws: WebSocket | null = null;
 47→let _connectionId: string | null = null;
 48→let connected = false;
 49→let connecting = false;
 50→let reconnectAttempt = 0;
 51→let reconnectTimer: ReturnType<typeof setTimeout> | null = null;
 52→let subCounter = 0;
 53→
 54→/** Active subscriptions keyed by client-assigned ID. */
 55→const subscriptions = new Map<string, Subscription>();
 56→
 57→/** Pending commands waiting for q:command_ack. */
 58→const pendingCommands = new Map<string, PendingCommand>();
 59→
 60→/** Listeners for q:event broadcasts. */
 61→const eventListeners = new Set<EventCallback>();
 62→
 63→/** Listeners notified when connection state changes (connected/disconnected). */
 64→const connectionChangeListeners = new Set<(connected: boolean) => void>();
 65→
 66→/** Counter for generating unique command frame IDs. */
 67→let commandCounter = 0;
 68→
 69→/** Resolvers waiting for the initial "connected" frame after open. */
 70→let connectResolve: (() => void) | null = null;
 71→let connectReject: ((err: Error) => void) | null = null;
 72→
 73→// ---- Public API ----
 74→
 75→/** Generate a unique subscription ID. */
 76→function nextSubId(): string {
 77→  return `sub_${++subCounter}`;
 78→}
 79→
 80→/**
 81→ * Connect to the backend WebSocket. Resolves once authenticated.
 82→ * No-op if already connected or connecting.
 83→ */
 84→export async function connect(): Promise<void> {
 85→  if (connected) return;
 86→  if (connecting) {
 87→    // Wait for the in-flight connection attempt
 88→    return new Promise<void>((resolve, reject) => {
 89→      const prevResolve = connectResolve;
 90→      const prevReject = connectReject;
 91→      connectResolve = () => {
 92→        prevResolve?.();
 93→        resolve();
 94→      };
 95→      connectReject = (err) => {
 96→        prevReject?.(err);
 97→        reject(err);
 98→      };
 99→    });
100→  }
101→
102→  connecting = true;
103→
104→  return new Promise<void>((resolve, reject) => {
105→    connectResolve = resolve;
106→    connectReject = reject;
107→    openSocket().catch((err) => {
108→      connecting = false;
109→      connectReject?.(err);
110→      connectResolve = null;
111→      connectReject = null;
112→    });
113→  });
114→}
115→
116→/**
117→ * Subscribe to a query resource. Returns an unsubscribe function.
118→ *
119→ * On subscription, the server sends an initial q:snapshot. Subsequent
120→ * invalidations push q:snapshot (full replace) or q:delta (incremental).
121→ */
122→export function subscribe(
123→  resource: QueryResource,
124→  params: Record<string, unknown> | undefined,
125→  onSnapshot: SnapshotCallback,
126→  onDelta?: DeltaCallback
127→): () => void {
128→  const id = nextSubId();
129→  const sub: Subscription = { id, resource, params, onSnapshot, onDelta };
130→  subscriptions.set(id, sub);
131→
132→  // If connected, send subscribe frame immediately
133→  if (connected && ws) {
134→    sendFrame({
135→      type: "q:subscribe",
136→      id,
137→      resource,
138→      ...(params ? { params } : {}),
139→    });
140→  }
141→
142→  // Return unsubscribe function
143→  return () => {
144→    subscriptions.delete(id);
145→    if (connected && ws) {
146→      sendFrame({ type: "q:unsubscribe", id });
147→    }
148→  };
149→}
150→
151→/** Check if the client is currently connected. */
152→export function isConnected(): boolean {
153→  return connected;
154→}
155→
156→/**
157→ * Send an async command via the q:command frame.
158→ * Used by upcoming cloud/relay feature -- no desktop consumer yet.
159→ * Returns a promise that resolves when the server sends q:command_ack.
160→ */
161→export function sendCommand(
162→  command: CommandName,
163→  params: Record<string, unknown>
164→): Promise<{ accepted: boolean; commandId?: string; error?: string }> {
165→  const id = `cmd_${++commandCounter}`;
166→
167→  return new Promise((resolve, reject) => {
168→    pendingCommands.set(id, { resolve, reject });
169→
170→    sendFrame({
171→      type: "q:command",
172→      id,
173→      command,
174→      params,
175→    });
176→
177→    // Timeout after 30s to prevent leaked promises
178→    setTimeout(() => {
179→      if (pendingCommands.has(id)) {
180→        pendingCommands.delete(id);
181→        reject(new Error(`Command ${command} timed out`));
182→      }
183→    }, 30_000);
184→  });
185→}
186→
187→/**
188→ * Register a callback for q:event broadcasts.
189→ * Used by upcoming cloud/relay feature -- no desktop consumer yet.
190→ * Returns an unregister function.
191→ */
192→export function onEvent(callback: EventCallback): () => void {
193→  eventListeners.add(callback);
194→  return () => {
195→    eventListeners.delete(callback);
196→  };
197→}
198→
199→/**
200→ * Register a callback for connection state changes.
201→ * Fires with `true` when connected, `false` when disconnected.
202→ * Used by useQuerySubscription to re-evaluate subscriptions after reconnect.
203→ * Returns an unregister function.
204→ */
205→export function onConnectionChange(callback: (connected: boolean) => void): () => void {
206→  connectionChangeListeners.add(callback);
207→  return () => {
208→    connectionChangeListeners.delete(callback);
209→  };
210→}
211→
212→// ---- Internal ----
213→
214→async function openSocket(): Promise<void> {
215→  const port = await getBackendPort();
216→  const url = `ws://localhost:${port}/ws`;
217→
218→  ws = new WebSocket(url);
219→
220→  ws.onopen = () => {
221→    // Localhost connections are auto-authenticated by the backend.
222→    // Wait for the "connected" frame in onmessage.
223→  };
224→
225→  ws.onmessage = (evt) => {
226→    let msg: Record<string, unknown>;
227→    try {
228→      msg = JSON.parse(evt.data as string);
229→    } catch {
230→      return;
231→    }
232→
233→    const type = typeof msg.type === "string" ? msg.type : "";
234→
235→    match(type)
236→      .with("connected", () => {
237→        _connectionId = msg.connectionId as string;
238→        connected = true;
239→        connecting = false;
240→        reconnectAttempt = 0;
241→
242→        // Re-subscribe all active subscriptions (reconnect scenario)
243→        resubscribeAll();
244→
245→        // Notify hooks that connection is available so they can set up subscriptions
246→        notifyConnectionChange(true);
247→
248→        connectResolve?.();
249→        connectResolve = null;
250→        connectReject = null;
251→      })
252→      .with("ping", () => {
253→        sendFrame({ type: "pong" });
254→      })
255→      .with("q:snapshot", () => {
256→        const sub = subscriptions.get(msg.id as string);
257→        sub?.onSnapshot(msg.data);
258→      })
259→      .with("q:delta", () => {
260→        const sub = subscriptions.get(msg.id as string);
261→        sub?.onDelta?.(
262→          msg.upserted as unknown[] | undefined,
263→          msg.removed as string[] | undefined,
264→          msg.cursor as number | undefined
265→        );
266→      })
267→      .with("q:command_ack", () => {
268→        const pending = pendingCommands.get(msg.id as string);
269→        if (pending) {
270→          pendingCommands.delete(msg.id as string);
271→          pending.resolve({
272→            accepted: msg.accepted as boolean,
273→            commandId: msg.commandId as string | undefined,
274→            error: msg.error as string | undefined,
275→          });
276→        }
277→      })
278→      .with("q:event", () => {
279→        const event = msg.event as string;
280→        const data = msg.data;
281→        for (const cb of eventListeners) {
282→          try {
283→            cb(event, data);
284→          } catch (err) {
285→            console.error("[WS] Event listener error:", err);
286→          }
287→        }
288→      })
289→      .with("q:error", () => {
290→        console.warn("[WS] Query error:", msg.message, "for sub:", msg.id);
291→      })
292→      .otherwise(() => {
293→        // Ignore unknown frame types (q:response, q:mutate_result, etc.)
294→      });
295→  };
296→
297→  ws.onerror = () => {
298→    // onerror fires before onclose — actual cleanup happens in onclose
299→  };
300→
301→  ws.onclose = () => {
302→    const wasConnected = connected;
303→    connected = false;
304→    _connectionId = null;
305→    ws = null;
306→
307→    // Reject all pending commands immediately — they can't succeed without a connection
308→    for (const [_id, pending] of pendingCommands) {
309→      pending.reject(new Error("WebSocket disconnected"));
310→    }
311→    pendingCommands.clear();
312→
313→    if (connecting) {
314→      // Initial connection failed — reject the connect() promise
315→      connecting = false;
316→      connectReject?.(new Error("WebSocket connection failed"));
317→      connectResolve = null;
318→      connectReject = null;
319→    }
320→
321→    if (wasConnected) {
322→      notifyConnectionChange(false);
323→    }
324→
325→    // Only auto-reconnect if we had previously connected or have active subscriptions
326→    if (wasConnected || subscriptions.size > 0) {
327→      scheduleReconnect();
328→    }
329→  };
330→}
331→
332→/** Notify all connection change listeners. */
333→function notifyConnectionChange(state: boolean): void {
334→  for (const cb of connectionChangeListeners) {
335→    try {
336→      cb(state);
337→    } catch (err) {
338→      console.error("[WS] Connection change listener error:", err);
339→    }
340→  }
341→}
342→
343→function sendFrame(frame: Record<string, unknown>): void {
344→  if (ws && ws.readyState === WebSocket.OPEN) {
345→    try {
346→      ws.send(JSON.stringify(frame));
347→    } catch {
348→      // Connection may have closed between readyState check and send
349→    }
350→  }
351→}
352→
353→/** Re-subscribe all active subscriptions after reconnect. */
354→function resubscribeAll(): void {
355→  for (const sub of subscriptions.values()) {
356→    sendFrame({
357→      type: "q:subscribe",
358→      id: sub.id,
359→      resource: sub.resource,
360→      ...(sub.params ? { params: sub.params } : {}),
361→    });
362→  }
363→}
364→
365→/** Schedule a reconnection with exponential backoff. */
366→function scheduleReconnect(): void {
367→  if (reconnectTimer) return;
368→
369→  const delay = Math.min(BACKOFF_BASE_MS * Math.pow(2, reconnectAttempt), BACKOFF_MAX_MS);
370→  reconnectAttempt++;
371→
372→  if (import.meta.env.DEV) {
373→    console.log(`[WS] Reconnecting in ${delay}ms (attempt ${reconnectAttempt})`);
374→  }
375→
376→  reconnectTimer = setTimeout(() => {
377→    reconnectTimer = null;
378→    connecting = true;
379→
380→    // Set up resolve/reject so subscriptions get re-established
381→    connectResolve = null;
382→    connectReject = null;
383→
384→    openSocket().catch(() => {
385→      connecting = false;
386→      // onclose handler will schedule another reconnect
387→    });
388→  }, delay);
389→}
