504→/**
505→ * Update system prompt mutation with optimistic update
506→ */
507→export function useUpdateSystemPrompt() {
508→  const queryClient = useQueryClient();
509→
510→  return useMutation({
511→    mutationFn: ({ workspaceId, systemPrompt }: { workspaceId: string; systemPrompt: string }) =>
512→      WorkspaceService.updateSystemPrompt(workspaceId, systemPrompt),
513→
514→    // Optimistic update: Show new prompt immediately
515→    onMutate: async ({ workspaceId, systemPrompt }) => {
516→      await queryClient.cancelQueries({
517→        queryKey: queryKeys.workspaces.systemPrompt(workspaceId),
518→      });
519→
520→      const previousPrompt = queryClient.getQueryData<string>(
521→        queryKeys.workspaces.systemPrompt(workspaceId)
522→      );
523→
524→      queryClient.setQueryData(queryKeys.workspaces.systemPrompt(workspaceId), systemPrompt);
525→
526→      return { previousPrompt };
527→    },
528→
529→    onError: (_err, variables, context) => {
530→      if (context?.previousPrompt !== undefined) {
531→        queryClient.setQueryData(
532→          queryKeys.workspaces.systemPrompt(variables.workspaceId),
533→          context.previousPrompt
534→        );
535→      }
536→    },
537→
538→    onSettled: (_, __, variables) => {
