 80→export const NOTIFY_SESSION_STATUS = "session:status" as const;
 81→export const NOTIFY_SESSION_UPDATED = "session:updated" as const;
 82→export const SIDECAR_NOTIFY_EVENTS = [
 83→  NOTIFY_SESSION_MESSAGE,
 84→  NOTIFY_SESSION_STATUS,
 85→  NOTIFY_SESSION_UPDATED,
 86→] as const;
