  1→// backend/src/services/query-engine.ts
  2→// Query engine — handles q:* protocol frames for typed reactive queries.
  3→// Module singleton: subscription state + dispatch logic.
  4→// Works for both local WS and relay-tunneled connections via WsSendable.
  5→//
  6→// Subscription model: ID-keyed. Client assigns IDs ("sub_1", "sub_2") and
  7→// server echoes them back on q:snapshot/q:delta so the client can route
  8→// to the correct callback.
  9→
 10→import { match } from "ts-pattern";
 11→import { getDatabase } from "../lib/database";
 12→import {
 13→  getDashboardWorkspaces,
 14→  getStats,
 15→  getSessionsByWorkspaceId,
 16→  getSessionById,
 17→  getMessages,
 18→  hasOlderMessages,
 19→  hasNewerMessages,
 20→  getWorkspaceRaw,
 21→  getMaxMessageSeq,
 22→  getMessagesDelta,
 23→  resetStatsCache,
 24→  getWorkspacesByRepo,
 25→  getWorkspacesBySessionIds,
 26→  getAllRepositorySummaries,
 27→  getSessionRaw,
 28→} from "../db";
 29→import { computeWorkspacePath } from "../middleware/workspace-loader";
 30→import { writeUserMessage } from "./message-writer";
 31→import { getConnection } from "./ws.service";
 32→import {
 33→  QUERY_RESOURCES,
 34→  MUTATION_NAMES,
 35→  COMMAND_NAMES,
 36→  type MutationName,
 37→  type CommandName,
 38→  type QueryResource,
 39→  type QServerFrame,
 40→} from "../../../shared/types/query-protocol";
 41→
 42→// ---- Subscription State ----
 43→
 44→type QueryParams = Record<string, unknown>;
 45→
 46→interface ResourceFrameInput {
 47→  id: string;
 48→  resource: string;
 49→  params: QueryParams;
 50→}
 51→
 52→interface UnsubscribeFrameInput {
 53→  id: string;
 54→}
 55→
 56→interface MutateFrameInput {
 57→  id: string;
 58→  action: string;
 59→  params: QueryParams;
 60→}
 61→
 62→interface CommandFrameInput {
 63→  id: string;
 64→  command: string;
 65→  params: QueryParams;
 66→}
 67→
 68→interface Sub {
 69→  id: string;
 70→  resource: QueryResource;
 71→  params: QueryParams;
 72→}
 73→
 74→/** Per-connection active subscriptions, keyed by client-assigned sub ID. */
 75→const subs = new Map<string, Map<string, Sub>>();
 76→
 77→/** For messages: track last seen seq per subscription for delta push.
 78→ *  Key: `${connectionId}:${subId}` → lastSeq */
 79→const messageCursors = new Map<string, number>();
 80→
 81→// ---- Public API ----
 82→
 83→/**
 84→ * Handle an incoming q:* frame from an authenticated connection.
 85→ * Registered as onQueryFrame in ws.service protocol handlers.
 86→ */
 87→export function handleFrame(connectionId: string, msg: QueryParams): void {
 88→  const type = typeof msg.type === "string" ? msg.type : "unknown";
 89→
 90→  try {
 91→    match(type)
 92→      .with("q:request", () => {
 93→        handleRequest(connectionId, parseResourceFrame(msg));
 94→      })
 95→      .with("q:subscribe", () => {
 96→        handleSubscribe(connectionId, parseResourceFrame(msg));
 97→      })
 98→      .with("q:unsubscribe", () => {
 99→        handleUnsubscribe(connectionId, parseUnsubscribeFrame(msg));
100→      })
101→      .with("q:mutate", () => {
102→        handleMutate(connectionId, parseMutateFrame(msg));
103→      })
104→      .with("q:command", () => {
105→        handleCommand(connectionId, parseCommandFrame(msg));
106→      })
107→      .otherwise(() => {
108→        sendFrame(connectionId, {
109→          type: "q:error",
110→          id: getFrameId(msg),
111→          code: "UNKNOWN_FRAME",
112→          message: `Unknown query frame type: ${type}`,
113→        });
114→      });
115→  } catch (err) {
116→    sendFrame(connectionId, {
117→      type: "q:error",
118→      id: getFrameId(msg),
119→      code: "INVALID_FRAME",
120→      message: err instanceof Error ? err.message : "Invalid query frame",
121→    });
122→  }
123→}
124→
125→/** Remove all subscriptions for a connection (cleanup on disconnect). */
126→export function removeSubs(connectionId: string): void {
127→  const connSubs = subs.get(connectionId);
128→  if (connSubs) {
129→    for (const [subId, sub] of connSubs) {
130→      if (sub.resource === "messages") {
131→        messageCursors.delete(`${connectionId}:${subId}`);
132→      }
133→    }
134→    subs.delete(connectionId);
135→  }
136→}
137→
138→/** Optional context for targeted invalidation (e.g., which sessions changed). */
139→interface InvalidateContext {
140→  sessionIds?: string[];
141→}
142→
143→/**
144→ * Push-first invalidation: re-run queries for active subscribers and push
145→ * fresh snapshots or deltas.
146→ *
147→ * Messages use q:delta (cursor-based) instead of full snapshots.
148→ * When `ctx.sessionIds` is provided, workspace subscribers receive a targeted
149→ * q:delta (only the changed workspaces) instead of a full q:snapshot.
150→ */
151→export function invalidate(resources: QueryResource[], ctx?: InvalidateContext): void {
152→  if (resources.includes("stats")) {
153→    resetStatsCache();
154→  }
155→
156→  // Phase 1: Push fresh data to active subscribers
157→  for (const [connectionId, connSubs] of subs) {
158→    if (!getConnection(connectionId)) {
159→      removeSubs(connectionId);
160→      continue;
161→    }
162→
163→    for (const [subId, sub] of connSubs) {
164→      if (!resources.includes(sub.resource)) continue;
165→
166→      if (sub.resource === "messages") {
167→        // Messages: push delta (new messages since last cursor)
168→        pushMessageDelta(connectionId, subId, sub.params);
169→      } else if (sub.resource === "workspaces" && ctx?.sessionIds?.length) {
170→        // Workspaces with session context: try targeted delta
171→        try {
172→          const db = getDatabase();
173→          const changedWorkspaces = getWorkspacesBySessionIds(db, ctx.sessionIds);
174→          if (changedWorkspaces.length > 0) {
175→            const withPaths = changedWorkspaces.map(ws => ({
176→              ...ws,
177→              workspace_path: computeWorkspacePath(ws),
178→            }));
179→            sendFrame(connectionId, {
180→              type: "q:delta",
181→              id: subId,
182→              upserted: withPaths,
183→            });
184→          } else {
185→            // Session IDs didn't match any workspaces — fall back to full snapshot
186→            const data = runQuery(sub.resource, sub.params);
187→            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
188→          }
189→        } catch (err) {
190→          // Delta lookup failed — fall back to full snapshot
191→          console.error(`[QueryEngine] Workspace delta failed, falling back to snapshot:`, err);
192→          try {
193→            const data = runQuery(sub.resource, sub.params);
194→            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
195→          } catch (snapErr) {
196→            console.error(`[QueryEngine] Snapshot fallback also failed:`, snapErr);
197→          }
198→        }
199→      } else if (sub.resource === "session" && ctx?.sessionIds?.length) {
200→        // Session with context: only push if this subscription's session is in the changed set
201→        const subscribedSessionId = readStringParam(sub.params, "sessionId");
202→        if (subscribedSessionId && ctx.sessionIds.includes(subscribedSessionId)) {
203→          try {
204→            const data = runQuery(sub.resource, sub.params);
205→            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
206→          } catch (err) {
207→            console.error(`[QueryEngine] Session snapshot push failed:`, err);
208→          }
209→        }
210→        // If session not in changed set, skip the push
211→      } else {
212→        // Other resources: push full snapshot
213→        try {
214→          const data = runQuery(sub.resource, sub.params);
215→          sendFrame(connectionId, {
216→            type: "q:snapshot",
217→            id: subId,
218→            data,
219→          });
220→        } catch (err) {
221→          console.error(`[QueryEngine] Snapshot push failed for ${sub.resource}:`, err);
222→        }
223→      }
224→    }
225→  }
226→
227→}
228→
229→// ---- Frame Handlers ----
230→
231→function handleRequest(connectionId: string, msg: ResourceFrameInput): void {
232→  const { id, resource, params } = msg;
233→
234→  try {
235→    const typedResource = toQueryResource(resource);
236→    const data = runQuery(typedResource, params);
237→    sendFrame(connectionId, { type: "q:response", id, data });
238→  } catch (err) {
239→    sendFrame(connectionId, {
240→      type: "q:error",
241→      id,
242→      code: "QUERY_ERROR",
243→      message: err instanceof Error ? err.message : "Query failed",
244→    });
245→  }
246→}
247→
248→function handleSubscribe(connectionId: string, msg: ResourceFrameInput): void {
249→  const { id, resource, params } = msg;
250→
251→  // Validate resource upfront — fail fast before running query
252→  const typedResource = toQueryResource(resource);
253→
254→  // Send initial snapshot — only register subscription if query succeeds
255→  // (avoids zombie subscriptions when runQuery throws on invalid params)
256→  try {
257→    const data = runQuery(typedResource, params);
258→
259→    // Get or create subscription map for this connection
260→    let connSubs = subs.get(connectionId);
261→    if (!connSubs) {
262→      connSubs = new Map();
263→      subs.set(connectionId, connSubs);
264→    }
265→
266→    // Store subscription by client-assigned ID (replaces if same ID reused on reconnect)
267→    connSubs.set(id, { id, resource: typedResource, params });
268→
269→    // For messages: initialize cursor to current max seq
270→    if (typedResource === "messages") {
271→      const sessionId = readStringParam(params, "sessionId");
272→      const cursorKey = `${connectionId}:${id}`;
273→      if (sessionId) {
274→        try {
275→          const db = getDatabase();
276→          messageCursors.set(cursorKey, getMaxMessageSeq(db, sessionId));
277→        } catch {
278→          messageCursors.set(cursorKey, 0);
279→        }
280→      }
281→    }
282→
283→    sendFrame(connectionId, { type: "q:snapshot", id, data });
284→  } catch (err) {
285→    sendFrame(connectionId, {
286→      type: "q:error",
287→      id,
288→      code: "SUBSCRIBE_ERROR",
289→      message: err instanceof Error ? err.message : "Subscribe failed",
290→    });
291→  }
292→}
293→
294→function handleUnsubscribe(connectionId: string, msg: UnsubscribeFrameInput): void {
295→  const { id } = msg;
296→
297→  const connSubs = subs.get(connectionId);
298→  if (!connSubs) return;
299→
300→  const sub = connSubs.get(id);
301→  if (sub) {
302→    // Clean up message cursor
303→    if (sub.resource === "messages") {
304→      messageCursors.delete(`${connectionId}:${id}`);
305→    }
306→    connSubs.delete(id);
307→    if (connSubs.size === 0) subs.delete(connectionId);
308→  }
309→}
310→
311→function handleMutate(connectionId: string, msg: MutateFrameInput): void {
312→  const { id, action, params } = msg;
313→
314→  try {
315→    const result = runMutation(action, params);
316→    sendFrame(connectionId, {
317→      type: "q:mutate_result",
318→      id,
319→      success: true,
320→      data: result,
321→    });
322→  } catch (err) {
323→    sendFrame(connectionId, {
324→      type: "q:mutate_result",
325→      id,
326→      success: false,
327→      error: err instanceof Error ? err.message : "Mutation failed",
328→    });
329→  }
330→}
331→
332→function handleCommand(connectionId: string, msg: CommandFrameInput): void {
333→  const { id, command, params } = msg;
334→
335→  try {
336→    const result = runCommand(command, params);
337→    sendFrame(connectionId, {
338→      type: "q:command_ack",
339→      id,
340→      accepted: true,
341→      ...result,
342→    } satisfies QServerFrame);
343→  } catch (err) {
344→    sendFrame(connectionId, {
345→      type: "q:command_ack",
346→      id,
347→      accepted: false,
348→      error: err instanceof Error ? err.message : "Command failed",
349→    } satisfies QServerFrame);
350→  }
351→}
