  1→/**
  2→ * Unix Socket Service
  3→ *
  4→ * Real-time communication with sidecar-v2 via Unix Domain Socket
  5→ *
  6→ * Architecture:
  7→ * React → Tauri invoke → Rust → Unix Socket → Sidecar-v2 → Claude SDK
  8→ *
  9→ * Protocol: JSON-RPC 2.0 over NDJSON
 10→ *
 11→ * Note: In web mode (non-Tauri), this service is disabled and returns mock responses
 12→ */
 13→
 14→import { invoke, isTauriEnv } from "@/platform/tauri";
 15→import type { AgentType } from "@shared/enums";
 16→import { QueryAckResponseSchema, SIDECAR_METHODS } from "@shared/protocol";
 17→import type { CancelRequest, QueryAckResponse, QueryOptions, QueryRequest } from "@shared/protocol";
 18→
 19→// Re-export shared types for downstream consumers
 20→export type { QueryAckResponse, QueryOptions };
 21→
 22→/**
 23→ * Unix Socket Service (Singleton)
 24→ *
 25→ * Manages JSON-RPC 2.0 communication with sidecar-v2
 26→ */
 27→class UnixSocketService {
 28→  private socketPath: string | null = null;
 29→  private connected: boolean = false;
 30→  private rpcIdCounter: number = 0;
 31→
 32→  /**
 33→   * Initialize connection to sidecar-v2 Unix socket
 34→   * Socket path is obtained from Rust SidecarManager (auto-discovered on startup)
 35→   */
 36→  async connect(): Promise<void> {
 37→    // Skip in web mode (non-Tauri)
 38→    if (!isTauriEnv) {
 39→      if (import.meta.env.DEV)
 40→        console.log("[SOCKET] ⚠️  Running in web mode - socket features disabled");
 41→      return;
 42→    }
 43→
 44→    try {
 45→      // Check if Rust already connected during app startup (avoids double-connection bug)
 46→      const alreadyConnected = await invoke<boolean>("is_sidecar_connected");
 47→      if (alreadyConnected) {
 48→        this.socketPath = await invoke<string | null>("get_sidecar_socket_path");
 49→        this.connected = true;
 50→        if (import.meta.env.DEV) console.log("[SOCKET] ✅ Already connected (Rust auto-connected)");
 51→        return;
 52→      }
 53→
 54→      // Get socket path from Rust SidecarManager (not HTTP endpoint)
 55→      const socketPath = await invoke<string | null>("get_sidecar_socket_path");
 56→
 57→      if (!socketPath) {
 58→        throw new Error("Sidecar socket path not available (sidecar-v2 may not be running)");
 59→      }
 60→
 61→      this.socketPath = socketPath;
 62→
 63→      // Connect via Tauri Rust
 64→      await invoke("connect_to_sidecar", { socketPath: this.socketPath });
 65→
 66→      this.connected = true;
 67→      if (import.meta.env.DEV) console.log("[SOCKET] ✅ Connected to sidecar-v2:", this.socketPath);
 68→    } catch (error) {
 69→      console.error("[SOCKET] ❌ Connection failed:", error);
 70→      throw error;
 71→    }
 72→  }
 73→
 74→  /**
 75→   * Send JSON-RPC request (expects response)
 76→   */
 77→  async request<T>(method: string, params: Record<string, unknown>): Promise<T> {
 78→    if (!this.connected && isTauriEnv) {
 79→      await this.connect();
 80→    }
 81→
 82→    if (!this.connected) {
 83→      throw new Error("Not connected to sidecar socket");
 84→    }
 85→
 86→    const id = ++this.rpcIdCounter;
 87→    const request = { jsonrpc: "2.0" as const, method, params, id };
 88→
 89→    let response: Record<string, unknown>;
 90→    try {
 91→      const messageStr = JSON.stringify(request);
 92→      await invoke("send_sidecar_message", { message: messageStr });
 93→
 94→      // Wait for response
 95→      const responseStr = await invoke<string>("receive_sidecar_message");
 96→      response = JSON.parse(responseStr);
 97→    } catch (error) {
 98→      // Transport-level failure (socket disconnected, Rust IPC error, timeout)
 99→      console.error("[SOCKET] ❌ Request failed:", error);
100→      this.connected = false;
101→      throw error;
102→    }
103→
104→    // Application-level JSON-RPC error — transport is healthy, sidecar
105→    // processed the request but returned an error response.
106→    if (response.error) {
107→      const rpcError = response.error as { message?: string };
108→      throw new Error(rpcError.message || "RPC error");
109→    }
110→
111→    return response.result as T;
112→  }
113→
114→  /**
115→   * Send agent query to sidecar-v2
116→   *
117→   * Sends a "query" request and waits for synchronous ACK/reject.
118→   * Streaming responses are received via Tauri events (session:message).
119→   */
120→  async sendQuery(
121→    sessionId: string,
122→    prompt: string,
123→    options: QueryOptions,
124→    agentType: AgentType = "claude"
125→  ): Promise<QueryAckResponse> {
126→    // Typed against QueryRequest — compiler catches shape mismatches
127→    // if shared/protocol.ts adds or changes fields.
128→    const params: QueryRequest = {
129→      type: "query",
130→      id: sessionId,
131→      agentType,
132→      prompt,
133→      options,
134→    };
135→    const raw = await this.request<QueryAckResponse>(SIDECAR_METHODS.QUERY, params);
136→    const parsed = QueryAckResponseSchema.safeParse(raw);
137→    if (!parsed.success) {
138→      console.error("[SOCKET] Invalid QueryAckResponse from sidecar:", parsed.error.message);
139→      return { accepted: false, reason: "Invalid response from sidecar" };
140→    }
141→
142→    if (import.meta.env.DEV)
143→      console.log("[SOCKET] 📤 Query sent to sidecar-v2:", sessionId.substring(0, 8), parsed.data);
144→
145→    return parsed.data;
146→  }
147→
148→  /**
149→   * Cancel an active query
150→   */
151→  async cancelQuery(
152→    sessionId: string,
153→    agentType: AgentType = "claude"
154→  ): Promise<void> {
155→    const params: CancelRequest = {
156→      type: "cancel",
157→      id: sessionId,
158→      agentType,
159→    };
160→    await this.request(SIDECAR_METHODS.CANCEL, params);
161→
162→    if (import.meta.env.DEV) console.log("[SOCKET] 🛑 Query cancelled:", sessionId.substring(0, 8));
163→  }
164→
165→  /**
166→   * Check if connected
167→   */
168→  isConnected(): boolean {
169→    return this.connected;
170→  }
171→}
172→
173→// Export singleton instance
174→export const socketService = new UnixSocketService();
175→

  1→/**
  2→ * Session Service
  3→ * API methods for Claude Code session management
  4→ */
  5→
  6→import { apiClient } from "@/shared/api/client";
  7→import { ENDPOINTS } from "@/shared/config/api.config";
  8→import { isTauriAvailable } from "@/platform/tauri/invoke";
  9→import { dbGetSession, dbGetMessages } from "@/platform/tauri/db";
 10→import type { Session, Message } from "../types";
 11→
 12→/** Pagination params for cursor-based message fetching (seq-based) */
 13→export interface MessagePaginationParams {
 14→  limit?: number;
 15→  before?: number; // seq cursor for older messages
 16→  after?: number; // seq cursor for newer messages
 17→}
 18→
 19→/** Paginated response shape from GET /sessions/:id/messages */
 20→export interface PaginatedMessages {
 21→  messages: Message[];
 22→  has_older: boolean;
 23→  has_newer: boolean;
 24→}
 25→
 26→export const SessionService = {
 27→  /**
 28→   * Fetch session by ID.
 29→   * Uses Rust/rusqlite via Tauri IPC when available (~1ms),
 30→   * falls back to Node.js HTTP when in web mode.
 31→   */
 32→  fetchById: async (id: string): Promise<Session> => {
 33→    if (isTauriAvailable()) {
 34→      try {
 35→        const session = await dbGetSession(id);
 36→        if (session) return session;
 37→      } catch {
 38→        // Rust DB failed — fall through to HTTP
 39→      }
 40→    }
 41→    return apiClient.get<Session>(ENDPOINTS.SESSION_BY_ID(id));
 42→  },
 43→
 44→  /**
 45→   * Fetch messages for a session with optional cursor-based pagination.
 46→   * Uses Rust/rusqlite via Tauri IPC when available (~1ms),
 47→   * falls back to Node.js HTTP when in web mode.
 48→   */
 49→  fetchMessages: async (
 50→    id: string,
 51→    params?: MessagePaginationParams
 52→  ): Promise<PaginatedMessages> => {
 53→    if (isTauriAvailable()) {
 54→      try {
 55→        return await dbGetMessages(id, {
 56→          limit: params?.limit,
 57→          before: params?.before,
 58→          after: params?.after,
 59→        });
 60→      } catch {
 61→        // Rust DB failed — fall through to HTTP
 62→      }
 63→    }
 64→    const searchParams = new URLSearchParams();
 65→    if (params?.limit != null) searchParams.set("limit", String(params.limit));
 66→    if (params?.before != null) searchParams.set("before", String(params.before));
 67→    if (params?.after != null) searchParams.set("after", String(params.after));
 68→    const qs = searchParams.toString();
 69→    const url = qs ? `${ENDPOINTS.SESSION_MESSAGES(id)}?${qs}` : ENDPOINTS.SESSION_MESSAGES(id);
 70→    return apiClient.get<PaginatedMessages>(url);
 71→  },
 72→
 73→  /**
 74→   * Send a message to a session
 75→   */
 76→  sendMessage: async (id: string, content: string, model?: string): Promise<Message> => {
 77→    return apiClient.post<Message>(ENDPOINTS.SESSION_MESSAGES(id), { content, model });
 78→  },
 79→
 80→  /**
 81→   * Stop a running session
 82→   */
 83→  stop: async (id: string): Promise<void> => {
 84→    return apiClient.post<void>(ENDPOINTS.SESSION_STOP(id));
 85→  },
 86→
 87→  /**
 88→   * Fetch all sessions for a workspace (used by chat tab reconstruction).
 89→   */
 90→  fetchByWorkspace: async (workspaceId: string): Promise<Session[]> => {
 91→    return apiClient.get<Session[]>(ENDPOINTS.WORKSPACE_SESSIONS(workspaceId));
 92→  },
 93→
 94→  /**
 95→   * Create a new session for a workspace.
 96→   * Also updates workspace.current_session_id to the new session.
 97→   */
 98→  createSession: async (workspaceId: string): Promise<Session> => {
 99→    return apiClient.post<Session>(ENDPOINTS.WORKSPACE_SESSIONS(workspaceId), {});
100→  },
101→};
