 93→): WriteResult {
 94→  const db = getDatabase();
 95→  const messageId = uuidv7();
 96→  const sentAt = new Date().toISOString();
 97→
 98→  // Store content blocks directly (flattened — no envelope wrapper).
 99→  const content = JSON.stringify(message.content ?? []);
100→
101→  try {
102→    db.prepare(
103→      `
104→      INSERT INTO messages (id, session_id, role, content, sent_at, agent_message_id, parent_tool_use_id)
105→      VALUES (?, ?, 'user', ?, ?, ?, ?)
106→    `
107→    ).run(messageId, sessionId, content, sentAt, message.id || null, parentToolUseId);
108→
109→    notifyBackend(NOTIFY_SESSION_MESSAGE, sessionId);
110→    return { ok: true, value: messageId };
111→  } catch (error) {
112→    const msg = getErrorMessage(error);
