118→// ── Save User Message (Atomic Send Path) ────────────────────────────────
119→
120→/**
121→ * Save a user message and set session status to "working" in a single
122→ * SQLite transaction. This is the sidecar-owns-send path: the frontend
123→ * sends one socket call, and the sidecar atomically persists the message
124→ * + activates the session before dispatching the agent.
125→ *
126→ * If the transaction fails, nothing is persisted — the frontend gets
127→ * { accepted: false } and can show a clean error without cleanup.
128→ */
129→export function saveUserMessage(
130→  sessionId: string,
131→  content: string,
132→  model: string = "opus"
133→): WriteResult {
134→  const db = getDatabase();
135→  const messageId = uuidv7();
136→  const sentAt = new Date().toISOString();
137→
138→  try {
139→    const saveAndActivate = db.transaction(() => {
140→      db.prepare(
141→        `INSERT INTO messages (id, session_id, role, content, sent_at, model)
142→         VALUES (?, ?, 'user', ?, ?, ?)`
143→      ).run(messageId, sessionId, content, sentAt, model);
144→
145→      db.prepare(
146→        `UPDATE sessions SET status = 'working', last_user_message_at = ?,
147→         error_message = NULL, error_category = NULL,
148→         updated_at = datetime('now') WHERE id = ?`
149→      ).run(sentAt, sessionId);
150→    });
151→
152→    saveAndActivate();
153→    notifyBackend(NOTIFY_SESSION_MESSAGE, sessionId);
154→
155→    // Emit statusChanged so the frontend receives a real Tauri event for
156→    // the working transition — not just the optimistic onMutate update.
157→    // If the socket ACK is lost and onError rolls back, this event re-corrects.
158→    try {
159→      const workspaceId = lookupWorkspaceId(sessionId);
160→      const agentType = lookupAgentType(sessionId);
161→      FrontendClient.sendStatusChanged({
162→        type: "status_changed",
163→        id: sessionId,
164→        agentType,
165→        status: "working",
166→        ...(workspaceId ? { workspaceId } : {}),
167→      });
168→    } catch {
169→      // No tunnel attached — frontend relies on optimistic update
170→    }
171→
172→    return { ok: true, value: messageId };
173→  } catch (error) {
174→    const msg = getErrorMessage(error);
175→    console.error(`[SESSION-WRITER] Failed to save user message:`, msg);
176→    return { ok: false, error: msg };
177→  }
178→}
