180→// ── Workspace Lookup ─────────────────────────────────────────────────────
181→
182→/**
183→ * Look up the workspace_id for a given session.
184→ * Used to include workspaceId in status events so the frontend can match
185→ * by workspace ID directly (more reliable than current_session_id matching
186→ * which breaks when a new session is created or on app startup).
187→ */
188→export function lookupWorkspaceId(sessionId: string): string | null {
189→  const db = getDatabase();
190→  try {
191→    const row = db.prepare("SELECT workspace_id FROM sessions WHERE id = ?").get(sessionId) as
192→      | { workspace_id: string }
193→      | undefined;
194→    return row?.workspace_id ?? null;
195→  } catch {
196→    return null;
197→  }
198→}
199→
200→/**
201→ * Look up the agent_type for a given session.
202→ * Used to include the correct agentType in status events instead of
203→ * hardcoding "claude" (which would be wrong for Codex sessions).
204→ */
205→export function lookupAgentType(sessionId: string): AgentType {
206→  const db = getDatabase();
207→  try {
208→    const row = db.prepare("SELECT agent_type FROM sessions WHERE id = ?").get(sessionId) as
209→      | { agent_type: string }
210→      | undefined;
211→    return (row?.agent_type as AgentType) ?? "claude";
212→  } catch {
213→    return "claude";
214→  }
215→}
216→
217→// ── Session Status ───────────────────────────────────────────────────────
218→
219→/**
220→ * Update session status (e.g., from 'working' to 'idle').
221→ * Called when a query completes (result.type === 'result' && result.subtype === 'success').
222→ *
223→ * busy_timeout PRAGMA (5000ms) handles SQLITE_BUSY retries at the driver level.
224→ */
225→export function updateSessionStatus(
226→  sessionId: string,
227→  status: SessionStatus,
228→  errorMessage?: string | null,
229→  errorCategory?: string | null
230→): WriteResult<void> {
231→  const t0 = Date.now();
232→  const db = getDatabase();
233→
234→  try {
235→    const tUpdate = Date.now();
236→    // busy_timeout PRAGMA (5000ms) handles SQLITE_BUSY retries at the driver level.
237→    // No application-level retry loop needed.
238→    db.prepare(
239→      `
240→      UPDATE sessions SET status = ?, error_message = ?, error_category = ?, updated_at = datetime('now') WHERE id = ?
241→    `
242→    ).run(
243→      status,
244→      status === "error" ? (errorMessage ?? null) : null,
245→      status === "error" ? (errorCategory ?? null) : null,
246→      sessionId
247→    );
248→    const updateMs = Date.now() - tUpdate;
249→
250→    const tNotify = Date.now();
251→    notifyBackend(NOTIFY_SESSION_STATUS, sessionId);
252→    const notifyMs = Date.now() - tNotify;
253→
254→    // Emit to frontend via Tauri event (desktop path).
255→    // Fire-and-forget: tunnel may not be attached during startup
256→    // (reconcileStuckSessions) or after sidecar restart.
257→    try {
258→      const workspaceId = lookupWorkspaceId(sessionId);
259→      const agentType = lookupAgentType(sessionId);
260→      FrontendClient.sendStatusChanged({
261→        type: "status_changed",
262→        id: sessionId,
263→        agentType,
264→        status,
265→        ...(status === "error" && errorMessage ? { errorMessage } : {}),
266→        ...(status === "error" && errorCategory
267→          ? { errorCategory: errorCategory as ErrorCategory }
268→          : {}),
269→        ...(workspaceId ? { workspaceId } : {}),
270→      });
271→    } catch {
272→      // No tunnel attached — frontend will pick up via fallback poll
273→    }
274→
275→    const totalMs = Date.now() - t0;
276→    console.log(
277→      `[TIMING][SESSION-WRITER] updateSessionStatus session=${sessionId} status='${status}' update=${updateMs}ms notify=${notifyMs}ms total=${totalMs}ms${errorMessage ? ` error: ${errorMessage}` : ""}`
278→    );
279→    return { ok: true, value: undefined };
280→  } catch (error) {
281→    const msg = getErrorMessage(error);
282→    console.error(`[SESSION-WRITER] Failed to update session status:`, msg);
283→    return { ok: false, error: msg };
284→  }
285→}
286→
287→// ── Agent Session ID (Resume Support) ────────────────────────────────
288→
289→/**
290→ * Persist the Claude Agent SDK session ID so the sidecar can resume
291→ * this conversation after a restart (sidecar crash, app relaunch).
292→ *
293→ * Called once per generator lifecycle — the first SDK message in the
294→ * for-await loop carries session_id, which is captured via a one-shot
295→ * boolean flag on SessionState.
296→ */
297→export function saveAgentSessionId(
298→  sessionId: string,
299→  agentSessionId: string | null
300→): WriteResult<void> {
301→  const db = getDatabase();
302→
303→  try {
304→    db.prepare(
305→      `
306→      UPDATE sessions SET agent_session_id = ?, updated_at = datetime('now') WHERE id = ?
307→    `
308→    ).run(agentSessionId, sessionId);
309→
310→    console.log(
311→      `[SESSION-WRITER] Saved agent_session_id ${agentSessionId} for session ${sessionId}`
312→    );
313→    return { ok: true, value: undefined };
314→  } catch (error) {
315→    const msg = getErrorMessage(error);
316→    console.error(`[SESSION-WRITER] Failed to save agent_session_id:`, msg);
317→    return { ok: false, error: msg };
318→  }
319→}
320→
321→/**
322→ * Look up the Claude Agent SDK session ID for a given app session.
323→ * Returns null if no agent_session_id has been captured yet (fresh session).
324→ *
325→ * Called by processWithGenerator before building SDK options to decide
326→ * whether to pass `resume: agentSessionId` to the SDK.
327→ */
328→export function lookupAgentSessionId(sessionId: string): string | null {
329→  const db = getDatabase();
330→
331→  try {
332→    const row = db.prepare("SELECT agent_session_id FROM sessions WHERE id = ?").get(sessionId) as
333→      | { agent_session_id: string | null }
334→      | undefined;
335→
336→    return row?.agent_session_id ?? null;
337→  } catch (error) {
338→    const msg = getErrorMessage(error);
339→    console.error(`[SESSION-WRITER] Failed to lookup agent_session_id:`, msg);
340→    return null;
341→  }
342→}
343→
344→// ── Startup Reconciliation ───────────────────────────────────────────
345→
346→/**
347→ * Reset sessions stuck in "working" status after a sidecar restart.
348→ *
349→ * When the sidecar dies (crash, app close), sessions remain in "working"
350→ * status in the DB because the finally block in processWithGenerator never
351→ * ran. This leaves them permanently stuck — the UI shows a spinner forever.
352→ *
353→ * Called once during sidecar startup, before accepting any connections.
354→ */
355→export function reconcileStuckSessions(): WriteResult<number> {
356→  const db = getDatabase();
357→
358→  try {
359→    // Log the state of all sessions before reconciliation for debugging resume issues
360→    const allSessions = db
361→      .prepare(
362→        `SELECT id, status, agent_session_id, error_message, error_category
363→         FROM sessions ORDER BY updated_at DESC LIMIT 20`
364→      )
365→      .all() as Array<{
366→      id: string;
367→      status: string;
368→      agent_session_id: string | null;
369→      error_message: string | null;
370→      error_category: string | null;
371→    }>;
372→
373→    console.debug(
374→      `[SESSION-WRITER] Session state at startup (${allSessions.length} recent sessions):`
375→    );
376→    for (const s of allSessions) {
377→      console.debug(
378→        `  [${s.id.substring(0, 8)}] status=${s.status} agent_session_id=${s.agent_session_id ?? "null"} error=${s.error_message ?? "none"} category=${s.error_category ?? "none"}`
379→      );
380→    }
381→
382→    const result = db
383→      .prepare(
384→        `
385→        UPDATE sessions SET status = 'idle', updated_at = datetime('now')
386→        WHERE status = 'working'
387→      `
388→      )
389→      .run();
390→
391→    const count = result.changes;
392→    if (count > 0) {
393→      console.log(`[SESSION-WRITER] Reconciled ${count} stuck session(s) from 'working' to 'idle'`);
394→    }
395→    return { ok: true, value: count };
396→  } catch (error) {
397→    const msg = getErrorMessage(error);
398→    console.error(`[SESSION-WRITER] Failed to reconcile stuck sessions:`, msg);
399→    return { ok: false, error: msg };
400→  }
401→}
