 1→// sidecar/db/backend-notifier.ts
 2→// Fire-and-forget HTTP POST to the backend to trigger instant dashboard updates.
 3→// Uses microtask coalescing (Beck's design): multiple writes in the same synchronous
 4→// call stack are batched into a single HTTP POST.
 5→
 6→import type { SidecarNotifyEvent } from "../../shared/events";
 7→
 8→const NOTIFY_URL = process.env.BACKEND_NOTIFY_URL;
 9→
10→// Pending notifications to be sent in the next microtask
11→let pending: Array<{ event: SidecarNotifyEvent; sessionId?: string }> | null = null;
12→
13→/**
14→ * Notify the backend that something changed in the DB.
15→ * Fire-and-forget: never throws, never blocks the write path.
16→ *
17→ * Uses queueMicrotask to coalesce rapid-fire writes (e.g., during streaming
18→ * where 10+ messages/sec arrive) into a single HTTP POST per event loop tick.
19→ */
20→export function notifyBackend(event: SidecarNotifyEvent, sessionId?: string): void {
21→  if (!NOTIFY_URL) return;
22→
23→  if (!pending) {
24→    pending = [];
25→    queueMicrotask(flush);
26→  }
27→  pending.push({ event, sessionId });
28→}
29→
30→function flush(): void {
31→  if (!NOTIFY_URL) return;
32→  const batch = pending;
33→  pending = null;
34→  if (!batch || batch.length === 0) return;
35→
36→  fetch(NOTIFY_URL, {
37→    method: "POST",
38→    headers: { "Content-Type": "application/json" },
39→    body: JSON.stringify({ notifications: batch }),
40→    signal: AbortSignal.timeout(5000),
41→  }).catch(() => {
42→    // Fire-and-forget: if backend is down, polling fallback handles it
43→  });
44→}
