 1→/**
 2→ * Connects the WebSocket query protocol client on app mount.
 3→ *
 4→ * All reactive data delivery happens through q:snapshot and q:delta pushed
 5→ * to active WS subscriptions — no separate invalidation bridge is needed.
 6→ */
 7→
 8→import { useEffect } from "react";
 9→import { connect } from "@/platform/ws";
10→
11→export function useQueryProtocol(): void {
12→  // Connect the WS client once on mount
13→  useEffect(() => {
14→    connect().catch((err) => {
15→      // Non-fatal: WS is additive. HTTP + Tauri events still work.
16→      if (import.meta.env.DEV) {
17→        console.warn("[QueryProtocol] WS connection failed:", err);
18→      }
19→    });
20→  }, []);
21→}
