411→/**
412→ * Archive workspace mutation with optimistic update
413→ *
414→ * Flow:
415→ * 1. User clicks archive → UI updates IMMEDIATELY (workspace removed from list)
416→ * 2. HTTP request sent in background
417→ * 3. Success: Cache already correct, refetch confirms
418→ * 4. Error: Rollback to previous state, show error
419→ */
420→export function useArchiveWorkspace() {
421→  const queryClient = useQueryClient();
422→  const queryKey = queryKeys.workspaces.byRepo("ready,initializing");
423→
424→  return useMutation({
425→    mutationFn: (workspaceId: string) => WorkspaceService.archive(workspaceId),
426→
427→    // Optimistic update: Remove workspace from UI immediately
428→    onMutate: async (workspaceId: string) => {
429→      // Cancel any outgoing refetches (so they don't overwrite our optimistic update)
430→      await queryClient.cancelQueries({ queryKey });
431→
432→      // Snapshot the previous value
433→      const previousData = queryClient.getQueryData<RepoGroup[]>(queryKey);
434→
435→      // Optimistically remove the workspace from the list
436→      queryClient.setQueryData<RepoGroup[]>(queryKey, (old) => {
437→        if (!old) return old;
438→        return produce(old, (draft) => {
439→          for (const repo of draft) {
440→            const index = repo.workspaces.findIndex((w) => w.id === workspaceId);
441→            if (index !== -1) {
442→              repo.workspaces.splice(index, 1);
443→              break;
444→            }
445→          }
446→        });
447→      });
448→
449→      // Return context with the previous value for rollback
450→      return { previousData };
451→    },
452→
453→    // If mutation fails, roll back to the previous value
454→    onError: (_err, _workspaceId, context) => {
455→      if (context?.previousData) {
456→        queryClient.setQueryData(queryKey, context.previousData);
457→      }
458→    },
459→
460→    onSuccess: (_data, workspaceId) => {
461→      track("workspace_archived", { workspace_id: workspaceId });
462→    },
463→
464→    // Always refetch after error or success to ensure consistency
465→    onSettled: () => {
466→      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
467→    },
468→  });
469→}
