125→/**
126→ * Send a q:* frame and wait for the next message matching the expected type.
127→ * Skips intermediate messages (e.g., legacy broadcasts) that don't match.
128→ */
129→function sendAndReceive(ws: WebSocket, frame: object, expectType: string, timeoutMs = 5000): Promise<any> {
130→  return new Promise((resolve, reject) => {
131→    const timeout = setTimeout(() => reject(new Error(`Timeout waiting for ${expectType}`)), timeoutMs);
132→    const handler = (evt: MessageEvent) => {
133→      const msg = JSON.parse(evt.data as string);
134→      if (msg.type === expectType) {
135→        clearTimeout(timeout);
136→        ws.removeEventListener("message", handler);
137→        resolve(msg);
138→      }
139→      // else: skip non-matching messages (legacy broadcasts, etc.)
140→    };
141→    ws.addEventListener("message", handler);
142→    ws.send(JSON.stringify(frame));
143→  });
144→}
145→
146→/**
147→ * Wait for the next message of a given type without sending anything.
148→ * Used after invalidate() to catch pushed snapshots/deltas.
149→ */
150→function waitForMessage(ws: WebSocket, expectType: string, timeoutMs = 3000): Promise<any> {
151→  return new Promise((resolve, reject) => {
152→    const timeout = setTimeout(() => reject(new Error(`Timeout waiting for ${expectType}`)), timeoutMs);
153→    const handler = (evt: MessageEvent) => {
154→      const msg = JSON.parse(evt.data as string);
155→      if (msg.type === expectType) {
156→        clearTimeout(timeout);
157→        ws.removeEventListener("message", handler);
158→        resolve(msg);
159→      }
160→    };
161→    ws.addEventListener("message", handler);
162→  });
163→}
164→
165→/**
166→ * Collect all messages within a time window. Resolves with the array.
167→ * Used to assert that NO messages are received (expect empty array).
168→ */
169→function collectMessages(ws: WebSocket, timeoutMs = 300): Promise<any[]> {
170→  return new Promise((resolve) => {
171→    const messages: any[] = [];
172→    const handler = (evt: MessageEvent) => {
173→      messages.push(JSON.parse(evt.data as string));
174→    };
175→    ws.addEventListener("message", handler);
176→    setTimeout(() => {
177→      ws.removeEventListener("message", handler);
178→      resolve(messages);
179→    }, timeoutMs);
180→  });
181→}
