 1→import { Hono } from 'hono';
 2→import { invalidate } from '../services/query-engine';
 3→import { NOTIFY_SESSION_MESSAGE, NOTIFY_SESSION_STATUS, NOTIFY_SESSION_UPDATED, SIDECAR_NOTIFY_EVENTS, type QueryResource, type SidecarNotifyEvent } from '../../../shared/events';
 4→
 5→const app = new Hono();
 6→
 7→/**
 8→ * POST /notify
 9→ *
10→ * Receives batched notifications from the sidecar after DB writes.
11→ * Triggers instant query-engine invalidation for connected clients.
12→ *
13→ * Notification events:
14→ * - session:message  → invalidate messages
15→ * - session:status   → invalidate workspaces, sessions, stats
16→ * - session:updated  → invalidate workspaces, sessions
17→ */
18→app.post('/notify', async (c) => {
19→  const { notifications } = await c.req.json<{
20→    notifications: Array<{ event: string; sessionId?: string }>;
21→  }>();
22→
23→  if (!Array.isArray(notifications) || notifications.length === 0) {
24→    return c.json({ ok: true });
25→  }
26→
27→  // Map sidecar events → query resources for push-first invalidation
28→  const INVALIDATION_MAP: Record<SidecarNotifyEvent, QueryResource[]> = {
29→    [NOTIFY_SESSION_MESSAGE]: ['messages', 'session'],
30→    [NOTIFY_SESSION_STATUS]:  ['workspaces', 'sessions', 'session', 'stats'],
31→    [NOTIFY_SESSION_UPDATED]: ['workspaces', 'sessions', 'session'],
32→  };
33→  const resourcesToInvalidate = new Set<QueryResource>();
34→
35→  for (const n of notifications) {
36→    if ((SIDECAR_NOTIFY_EVENTS as readonly string[]).includes(n.event)) {
37→      const resources = INVALIDATION_MAP[n.event as SidecarNotifyEvent];
38→      resources.forEach((r) => resourcesToInvalidate.add(r));
39→    }
40→  }
41→
42→  // Push-first invalidation for query subscribers
43→  if (resourcesToInvalidate.size > 0) {
44→    const sessionIds = notifications
45→      .filter(n => n.sessionId)
46→      .map(n => n.sessionId!);
47→    invalidate(
48→      [...resourcesToInvalidate],
49→      sessionIds.length > 0 ? { sessionIds } : undefined
50→    );
51→  }
52→
53→  return c.json({ ok: true });
54→});
55→
56→export default app;
