 77→app.get('/workspaces/:id', (c) => {
 78→  const db = getDatabase();
 79→  const workspace = getWorkspaceById(db, c.req.param('id'));
 80→  if (!workspace) throw new NotFoundError('Workspace not found');
 81→  return c.json({ ...workspace, workspace_path: computeWorkspacePath(workspace) });
 82→});
