251→// Create a new session for an existing workspace
252→app.post('/workspaces/:id/sessions', (c) => {
253→  const db = getDatabase();
254→  const workspaceId = c.req.param('id');
255→
256→  const workspace = getWorkspaceRaw(db, workspaceId);
257→  if (!workspace) throw new NotFoundError('Workspace not found');
258→
259→  const sessionId = uuidv7();
260→
261→  const createSession = db.transaction(() => {
262→    db.prepare(
263→      "INSERT INTO sessions (id, workspace_id, status, updated_at) VALUES (?, ?, 'idle', datetime('now'))"
264→    ).run(sessionId, workspaceId);
265→
266→    db.prepare(
267→      "UPDATE workspaces SET current_session_id = ?, updated_at = datetime('now') WHERE id = ?"
268→    ).run(sessionId, workspaceId);
269→  });
270→
271→  createSession();
272→  invalidate(['workspaces', 'sessions', 'stats']);
273→
274→  const session = getSessionRaw(db, sessionId);
275→  return c.json(session);
