278→// ─── Manifest & Task Endpoints ──────────────────────────────
279→
280→// Get parsed manifest + normalized tasks for a workspace
281→app.get('/workspaces/:id/manifest', withWorkspace, (c) => {
282→  const workspace = c.get('workspace');
283→  const workspacePath = c.get('workspacePath');
284→  if (!workspace.root_path) {
285→    return c.json({ manifest: null, tasks: [] });
286→  }
287→  const manifest = readManifestWithFallback(workspacePath, workspace.root_path);
288→  if (!manifest) return c.json({ manifest: null, tasks: [] });
289→  const tasks = getNormalizedTasks(manifest);
290→  return c.json({ manifest, tasks });
291→});
292→
293→// Retry failed setup
294→app.post('/workspaces/:id/retry-setup', withWorkspace, (c) => {
295→  const db = getDatabase();
296→  const workspace = c.get('workspace');
297→  const workspacePath = c.get('workspacePath');
298→
299→  if (workspace.setup_status !== 'failed') {
300→    throw new ValidationError('Can only retry when setup_status is failed');
301→  }
302→
303→  if (!workspace.root_path) {
304→    throw new ValidationError('Repository path not found');
305→  }
306→
307→  // Re-read manifest (AI agent may have fixed it, or it was added to repo root via settings)
308→  const manifest = readManifestWithFallback(workspacePath, workspace.root_path);
309→  const setupCmd = manifest ? getSetupCommand(manifest) : null;
310→  if (!setupCmd || !manifest) {
311→    db.prepare("UPDATE workspaces SET setup_status = 'none', error_message = NULL, updated_at = datetime('now') WHERE id = ?")
312→      .run(workspace.id);
313→    return c.json({ setup_status: 'none' });
314→  }
315→
316→  db.prepare("UPDATE workspaces SET setup_status = 'running', error_message = NULL, updated_at = datetime('now') WHERE id = ?")
317→    .run(workspace.id);
318→
319→  const setupEnv = getOpenDevsEnv(manifest, {
320→    id: workspace.id,
321→    rootPath: workspace.root_path,
322→    workspacePath,
323→  });
324→  runSetupScript(db, workspace.id, setupCmd, setupEnv, workspacePath);
325→
326→  return c.json({ setup_status: 'running' });
327→});
328→
329→// Get setup logs
330→app.get('/workspaces/:id/setup-logs', withWorkspace, (c) => {
331→  const workspace = c.get('workspace');
332→  const setupLogPath = path.join(os.tmpdir(), `opendevs-${workspace.id}-setup.log`);
333→  try {
334→    if (!fs.existsSync(setupLogPath)) return c.json({ logs: null });
335→    const logs = fs.readFileSync(setupLogPath, 'utf8');
336→    return c.json({ logs });
337→  } catch {
338→    return c.json({ logs: null });
339→  }
340→});
341→
342→// Run a task — validates task exists, returns info for frontend PTY spawn
343→app.post('/workspaces/:id/tasks/:name/run', withWorkspace, (c) => {
344→  const workspace = c.get('workspace');
345→  const workspacePath = c.get('workspacePath');
346→  const taskName = c.req.param('name');
347→
348→  if (!workspace.root_path) {
349→    throw new ValidationError('Repository path not found');
350→  }
351→
352→  const manifest = readManifestWithFallback(workspacePath, workspace.root_path);
353→  if (!manifest) throw new NotFoundError('No opendevs.json manifest found');
354→
355→  const tasks = getNormalizedTasks(manifest);
356→  const task = tasks.find(t => t.name === taskName);
357→  if (!task) throw new NotFoundError(`Task "${taskName}" not found in manifest`);
358→
359→  const ptyId = `task-${workspace.id}-${taskName}-${Date.now()}`;
360→  const env = {
361→    ...(manifest.env ?? {}),
362→    ...task.env,
363→    OPENDEVS_ROOT_PATH: workspace.root_path,
364→    OPENDEVS_WORKSPACE_PATH: workspacePath,
365→    OPENDEVS_WORKSPACE_ID: workspace.id,
366→  };
367→
368→  return c.json({
369→    ptyId,
370→    command: task.command,
371→    cwd: workspacePath,
372→    env,
373→    persistent: task.persistent,
374→    mode: task.mode,
375→  });
376→});
377→
378→export default app;
