  1→// Query protocol — WebSocket wire format for the cloud relay.
  2→// All frame types prefixed with "q:" so they route cleanly in the ws.service dispatcher.
  3→//
  4→// Domain constants (QUERY_RESOURCES, MUTATION_NAMES, SIDECAR_NOTIFY_EVENTS)
  5→// live in shared/events.ts — the single source of truth for all app events
  6→// and resources. This file only defines the wire format that carries them.
  7→
  8→import type { QueryResource, MutationName, CommandName, ProtocolEvent } from "../events";
  9→
 10→// Re-export so existing `import { QueryResource } from "query-protocol"` still works.
 11→export type { QueryResource, MutationName, CommandName, ProtocolEvent };
 12→export {
 13→  QUERY_RESOURCES,
 14→  MUTATION_NAMES,
 15→  COMMAND_NAMES,
 16→  PROTOCOL_EVENTS,
 17→  SIDECAR_NOTIFY_EVENTS,
 18→} from "../events";
 19→export type { SidecarNotifyEvent } from "../events";
 20→
 21→// ---- Client → Server Frames ----
 22→
 23→/** Client requests data (one-shot). */
 24→export interface QRequestFrame {
 25→  type: "q:request";
 26→  id: string;
 27→  resource: QueryResource;
 28→  params?: Record<string, unknown>;
 29→}
 30→
 31→/** Client subscribes to live updates for a resource. */
 32→export interface QSubscribeFrame {
 33→  type: "q:subscribe";
 34→  id: string;
 35→  resource: QueryResource;
 36→  params?: Record<string, unknown>;
 37→}
 38→
 39→/** Client unsubscribes by subscription ID (no resource/params needed). */
 40→export interface QUnsubscribeFrame {
 41→  type: "q:unsubscribe";
 42→  id: string;
 43→}
 44→
 45→/** Client requests a mutation. Field is `action`, not `mutation`. */
 46→export interface QMutateFrame {
 47→  type: "q:mutate";
 48→  id: string;
 49→  action: MutationName;
 50→  params: Record<string, unknown>;
 51→}
 52→
 53→/** Client sends an async command (e.g. sendMessage, stopSession). */
 54→export interface QCommandFrame {
 55→  type: "q:command";
 56→  id: string;
 57→  command: CommandName;
 58→  params: Record<string, unknown>;
 59→}
 60→
 61→/** All frames a client can send. */
 62→export type QClientFrame =
 63→  | QRequestFrame
 64→  | QSubscribeFrame
 65→  | QUnsubscribeFrame
 66→  | QMutateFrame
 67→  | QCommandFrame;
 68→
 69→// ---- Server → Client Frames ----
 70→
 71→/** Server returns data for a one-shot request. */
 72→export interface QResponseFrame {
 73→  type: "q:response";
 74→  id: string;
 75→  data: unknown;
 76→}
 77→
 78→/** Server pushes a full snapshot to a subscriber (keyed by subscription ID). */
 79→export interface QSnapshotFrame {
 80→  type: "q:snapshot";
 81→  id: string;
 82→  data: unknown;
 83→  cursor?: number;
 84→}
 85→
 86→/** Server pushes incremental update (keyed by subscription ID). */
 87→export interface QDeltaFrame {
 88→  type: "q:delta";
 89→  id: string;
 90→  upserted?: unknown[];
 91→  removed?: string[];
 92→  cursor?: number;
 93→}
 94→
 95→/** Server returns mutation result. Uses `success`, not `ok`. */
 96→export interface QMutateResultFrame {
 97→  type: "q:mutate_result";
 98→  id: string;
 99→  success: boolean;
100→  data?: unknown;
101→  error?: string;
102→}
103→
104→/** Server tells clients to refetch stale resources. */
105→export interface QInvalidateFrame {
106→  type: "q:invalidate";
107→  resources: QueryResource[];
108→}
109→
110→/** Server acknowledges an async command. */
111→export interface QCommandAckFrame {
112→  type: "q:command_ack";
113→  id: string;
114→  accepted: boolean;
115→  commandId?: string;
116→  error?: string;
117→}
118→
119→/** Server pushes an ephemeral event (no subscription needed). */
120→export interface QEventFrame {
121→  type: "q:event";
122→  event: string;
123→  data: unknown;
124→}
125→
126→/** Server error for a specific request. */
127→export interface QErrorFrame {
128→  type: "q:error";
129→  id: string;
130→  code: string;
131→  message: string;
132→}
133→
134→/** All frames a server can send. */
135→export type QServerFrame =
136→  | QResponseFrame
137→  | QSnapshotFrame
138→  | QDeltaFrame
139→  | QMutateResultFrame
140→  | QCommandAckFrame
141→  | QEventFrame
142→  | QInvalidateFrame
143→  | QErrorFrame;
