  1→/**
  2→ * Unix Domain Socket Client for Sidecar-v2 Communication
  3→ *
  4→ * Connects to the Node.js sidecar-v2 Unix socket for real-time
  5→ * communication with agent runtime (Claude SDK, Codex, etc.).
  6→ *
  7→ * ARCHITECTURE (Event Flow):
  8→ * Frontend → Tauri IPC → Rust socket relay → Sidecar-v2 → Claude SDK
  9→ * Claude responds → Sidecar-v2 saves to DB → Sidecar-v2 JSON-RPC notify
 10→ * → Rust listener (here) reads → Rust emits Tauri event → Frontend
 11→ * → UI updates instantly (<100ms latency)
 12→ *
 13→ * PROTOCOL: JSON-RPC 2.0 over newline-delimited JSON (NDJSON)
 14→ * Notifications from sidecar-v2 are logged but no longer emitted as Tauri events.
 15→ * Session data now flows via the backend WS query protocol (q:snapshot/q:delta).
 16→ *
 17→ * DESIGN DECISION - Why Unix Socket vs HTTP SSE:
 18→ * - Infrastructure already existed (sidecar uses Unix socket)
 19→ * - Tauri event system proven working (PTY integration)
 20→ * - No HTTP overhead for desktop app
 21→ * - ~150 lines vs ~200+ for SSE implementation
 22→ *
 23→ * PERFORMANCE FIX (2025-10-26):
 24→ * - Was: Busy-wait loop checking connection every 100ms (high CPU when disconnected)
 25→ * - Now: Sleep 1s when disconnected, 100ms when connected (90% CPU reduction)
 26→ *
 27→ * DATA CORRUPTION FIX (2026-02-05):
 28→ * - Was: Two independent BufReaders on the same fd (event listener via try_clone()
 29→ *   and receive() via direct stream read) raced for bytes, causing JSON-RPC
 30→ *   responses to be consumed by the wrong reader — data loss on cancelQuery(),
 31→ *   getClaudeAuth(), workspaceInit() while streaming was active.
 32→ * - Now: ALL reads go through the single event listener thread. JSON-RPC responses
 33→ *   (messages with an "id" field) are dispatched via mpsc channel to receive().
 34→ *   Notifications (no "id") are emitted as Tauri events as before.
 35→ */
 36→
 37→use std::io::{BufRead, BufReader, Write};
 38→use std::os::unix::net::UnixStream;
 39→use std::path::PathBuf;
 40→use std::sync::{Arc, Mutex, mpsc};
 41→use std::thread;
 42→use std::time::Duration;
 43→use tauri::{AppHandle, Emitter};
 44→use serde_json::Value;
 45→
 46→/**
 47→ * Socket Manager State
 48→ *
 49→ * Maintains connection to the sidecar Unix socket.
 50→ *
 51→ * All reads are funneled through the event listener thread to prevent
 52→ * data corruption from concurrent BufReaders on the same fd.
 53→ * JSON-RPC responses (with "id") are dispatched to response_rx for receive().
 54→ * JSON-RPC notifications (without "id") are emitted as Tauri events.
 55→ */
 56→pub struct SocketManager {
 57→    socket_path: Mutex<Option<PathBuf>>,
 58→    stream: Arc<Mutex<Option<UnixStream>>>,
 59→    app_handle: Arc<Mutex<Option<AppHandle>>>,
 60→    /// Channel receiver for JSON-RPC responses routed from the event listener.
 61→    /// Created fresh in start_event_listener(), cleared in disconnect().
 62→    response_rx: Arc<Mutex<Option<mpsc::Receiver<String>>>>,
 63→}
 64→
 65→impl SocketManager {
 66→    pub fn new() -> Self {
 67→        SocketManager {
 68→            socket_path: Mutex::new(None),
 69→            stream: Arc::new(Mutex::new(None)),
 70→            app_handle: Arc::new(Mutex::new(None)),
 71→            response_rx: Arc::new(Mutex::new(None)),
 72→        }
 73→    }
 74→
 75→    /**
 76→     * Set app handle for emitting Tauri events
 77→     */
 78→    pub fn set_app_handle(&self, handle: AppHandle) {
 79→        *self.app_handle.lock().unwrap() = Some(handle);
 80→    }
 81→
 82→    /**
 83→     * Connect to the sidecar Unix socket
 84→     *
 85→     * @param socket_path - Path to Unix socket (e.g., /tmp/opendevs-claude-12345.sock)
 86→     */
 87→    pub fn connect(&self, socket_path: String) -> Result<(), String> {
 88→        let path = PathBuf::from(&socket_path);
 89→
 90→        // Skip if already connected to the same socket path.
 91→        // This prevents the frontend's useSocket() from creating a second
 92→        // connection that splits reads (event listener) and writes (send).
 93→        {
 94→            let current_path = self.socket_path.lock().unwrap();
 95→            if let Some(ref existing) = *current_path {
 96→                if existing == &path {
 97→                    println!("[SOCKET] Already connected to {}", socket_path);
 98→                    return Ok(());
 99→                }
100→            }
101→        }
102→
103→        // Disconnect existing connection before connecting to a different path
104→        // to avoid leaking the old stream and stale response channel.
105→        {
106→            let has_existing = self.stream.lock().unwrap().is_some();
107→            if has_existing {
108→                println!("[SOCKET] Disconnecting from previous socket before connecting to new path");
109→                let _ = self.disconnect();
110→            }
111→        }
112→
113→        match UnixStream::connect(&path) {
114→            Ok(stream) => {
115→                *self.stream.lock().unwrap() = Some(stream);
116→                *self.socket_path.lock().unwrap() = Some(path);
117→                println!("[SOCKET] Connected to {}", socket_path);
118→                Ok(())
119→            }
120→            Err(e) => Err(format!("Failed to connect to socket: {}", e)),

120→            Err(e) => Err(format!("Failed to connect to socket: {}", e)),
121→        }
122→    }
123→
124→    /**
125→     * Send NDJSON message to sidecar
126→     *
127→     * @param message - JSON message to send
128→     */
129→    pub fn send(&self, message: String) -> Result<(), String> {
130→        let mut stream_lock = self.stream.lock().unwrap();
131→
132→        match stream_lock.as_mut() {
133→            Some(stream) => {
134→                // NDJSON format: JSON + newline
135→                let ndjson = format!("{}\n", message);
136→                stream
137→                    .write_all(ndjson.as_bytes())
138→                    .map_err(|e| format!("Failed to send message: {}", e))?;
139→                stream
140→                    .flush()
141→                    .map_err(|e| format!("Failed to flush: {}", e))?;
142→                Ok(())
143→            }
144→            None => Err("Not connected to socket".to_string()),
145→        }
146→    }
147→
148→    /**
149→     * Receive a JSON-RPC response from sidecar
150→     *
151→     * Instead of reading from the socket directly (which would race with the
152→     * event listener thread), this reads from the mpsc response channel that
153→     * the event listener populates with JSON-RPC response messages (those with
154→     * an "id" field).
155→     *
156→     * Uses a 30-second timeout to avoid hanging forever if the sidecar dies.
157→     */
158→    pub fn receive(&self) -> Result<String, String> {
159→        let rx_lock = self.response_rx.lock().unwrap();
160→
161→        match rx_lock.as_ref() {
162→            Some(rx) => {
163→                // Use recv_timeout to avoid blocking forever if sidecar dies
164→                // or the connection is dropped while we're waiting.
165→                rx.recv_timeout(Duration::from_secs(30))
166→                    .map_err(|e| match e {
167→                        mpsc::RecvTimeoutError::Timeout => {
168→                            "Timed out waiting for response from sidecar (30s)".to_string()
169→                        }
170→                        mpsc::RecvTimeoutError::Disconnected => {
171→                            "Response channel disconnected (event listener stopped)".to_string()
172→                        }
173→                    })
174→            }
175→            None => Err("Not connected to socket (no response channel)".to_string()),
176→        }
177→    }
178→
179→    /**
180→     * Start listening for broadcast events from sidecar-v2
181→     * Runs in background thread and emits Tauri events to frontend
182→     *
183→     * ALL socket reads are funneled through this single thread to prevent
184→     * data corruption from concurrent BufReaders on the same fd.
185→     *
186→     * Parses JSON-RPC 2.0 messages from sidecar-v2:
187→     * - Notifications (no "id"): logged but no longer emitted as Tauri events
188→     *   (session data flows via backend WS query protocol q:snapshot/q:delta)
189→     * - Responses (has "id"): dispatched to mpsc channel for receive()
190→     */
191→    pub fn start_event_listener(&self) {
192→        // Create the mpsc channel for routing JSON-RPC responses to receive()
193→        let (response_tx, response_rx) = mpsc::channel::<String>();
194→        *self.response_rx.lock().unwrap() = Some(response_rx);
195→
196→        let stream = Arc::clone(&self.stream);
197→        let app_handle = Arc::clone(&self.app_handle);
198→
199→        thread::spawn(move || {
200→            println!("[SOCKET] Event listener started (JSON-RPC 2.0 mode)");
201→
202→            loop {
203→                // Check if we have a connection
204→                let socket_opt = {
205→                    let stream_guard = stream.lock().unwrap();
206→                    stream_guard.as_ref().and_then(|s| s.try_clone().ok())
207→                };
208→
209→                if let Some(socket) = socket_opt {
210→                    let reader = BufReader::new(&socket);
211→
212→                    for line in reader.lines() {
213→                        match line {
214→                            Ok(line) => {
215→                                // Try to parse as JSON-RPC 2.0 message
216→                                if let Ok(rpc_msg) = serde_json::from_str::<Value>(&line) {
217→                                    let is_jsonrpc = rpc_msg.get("jsonrpc")
218→                                        .and_then(|v| v.as_str()) == Some("2.0");
219→
220→                                    if !is_jsonrpc {
221→                                        continue;
222→                                    }
223→
224→                                    // Dispatch based on message shape:
225→                                    // 1. Has "method" + "id" = sidecar→frontend REQUEST → emit Tauri event
226→                                    // 2. Has "id" but no "method" = response to frontend request → mpsc
227→                                    // 3. Has "method" but no "id" = notification → emit Tauri event
228→                                    let has_method = rpc_msg.get("method").and_then(|v| v.as_str()).is_some();
229→                                    let has_id = rpc_msg.get("id").is_some();
230→
231→                                    if has_method && has_id {
232→                                        // Sidecar → Frontend REQUEST (bidirectional RPC)
233→                                        // The sidecar is requesting the frontend to do something
234→                                        // (e.g., eval JS in browser, ask user a question).
235→                                        // Emit as "sidecar:request" with full JSON-RPC envelope.
236→                                        let method = rpc_msg.get("method").and_then(|v| v.as_str()).unwrap_or("unknown");
237→                                        println!("[SOCKET] Sidecar request: {} (id={})", method,
238→                                            rpc_msg.get("id").map(|v| v.to_string()).unwrap_or_default());
239→
240→                                        if let Some(handle) = app_handle.lock().unwrap().as_ref() {
241→                                            let payload = serde_json::json!({
242→                                                "id": rpc_msg.get("id"),
243→                                                "method": method,
244→                                                "params": rpc_msg.get("params").cloned().unwrap_or(Value::Null),
245→                                            });
246→                                            if let Err(e) = handle.emit("sidecar:request", payload) {
247→                                                eprintln!("[SOCKET] Failed to emit sidecar request: {}", e);
248→                                            }
249→                                        }
250→                                    } else if has_id {
251→                                        // Response to frontend-initiated request → route to receive()
252→                                        let _ = response_tx.send(line);
253→                                    } else if has_method {
254→                                        // Notification — emit as Tauri event
255→                                        let method = rpc_msg.get("method")
256→                                            .and_then(|v| v.as_str())
257→                                            .unwrap_or("unknown");
258→
259→                                        let params = rpc_msg.get("params").cloned()
260→                                            .unwrap_or(Value::Null);
261→
262→                                        // Session notifications (message, queryError, statusChanged,
263→                                        // enterPlanModeNotification) are now handled by the backend
264→                                        // query engine via WS q:snapshot/q:delta pushes. No Tauri
265→                                        // event mapping needed — the frontend reads from React Query
266→                                        // cache populated by the WS subscription.
267→                                        println!("[SOCKET] Ignoring RPC notification: {} (handled by WS query protocol)", method);
268→                                    }
269→                                }
270→                            }
271→                            Err(e) => {
272→                                eprintln!("[SOCKET] Error reading line: {}", e);
273→                                // Clear the stream so we don't spin in a tight loop
274→                                // trying to read from a broken connection
275→                                *stream.lock().unwrap() = None;
276→                                break; // Connection lost, exit loop
277→                            }
278→                        }
279→                    }
280→
281→                    // Wait a bit before checking again
282→                    thread::sleep(Duration::from_millis(100));
283→                } else {
284→                    // No connection - wait longer before retrying to avoid busy-wait
285→                    thread::sleep(Duration::from_secs(1));
286→                }
287→            }
288→        });
289→    }
290→
291→    /**
292→     * Disconnect from socket
293→     */
294→    pub fn disconnect(&self) -> Result<(), String> {
295→        *self.stream.lock().unwrap() = None;
296→        *self.socket_path.lock().unwrap() = None;
297→        // Clear the response channel so receive() returns an error immediately
298→        // instead of blocking on a stale channel.
299→        *self.response_rx.lock().unwrap() = None;
300→        println!("[SOCKET] Disconnected");
301→        Ok(())
302→    }
303→
304→    /**
305→     * Check if connected
306→     */
307→    pub fn is_connected(&self) -> bool {
308→        self.stream.lock().unwrap().is_some()
309→    }
310→}
