391→/**
392→ * Fetch available branches for a workspace/repo.
393→ * Uses Tauri IPC (fast, libgit2). Returns [] gracefully in browser/Storybook.
394→ */
395→export function useBranches(workspacePath: string | null) {
396→  return useQuery({
