  1→/**
  2→ * Hook that subscribes to a query protocol resource via WebSocket and writes
  3→ * snapshots/deltas directly into the React Query cache.
  4→ *
  5→ * This bypasses the HTTP refetch cycle: instead of
  6→ *   Tauri event -> invalidate -> HTTP GET -> render
  7→ * it becomes:
  8→ *   WS q:snapshot -> setQueryData -> render
  9→ *
 10→ * The HTTP queryFn remains as fallback for initial load (before WS connects)
 11→ * and for non-Tauri environments.
 12→ */
 13→
 14→import { useEffect, useMemo, useRef, useState } from "react";
 15→import { useQueryClient, type QueryKey } from "@tanstack/react-query";
 16→import { subscribe, isConnected, onConnectionChange } from "@/platform/ws";
 17→import type { QueryResource } from "@shared/types/query-protocol";
 18→
 19→interface UseQuerySubscriptionOptions {
 20→  /** React Query cache key to write data into. */
 21→  queryKey: QueryKey;
 22→  /** Optional params passed to the backend query (e.g., { state: "ready,initializing" }). */
 23→  params?: Record<string, unknown>;
 24→  /** Disable the subscription (e.g., when data isn't needed). Defaults to true. */
 25→  enabled?: boolean;
 26→  /** Custom delta merge. Receives old cache value + delta items, returns new cache value.
 27→   *  When provided, replaces the default flat-array merge for q:delta frames. */
 28→  mergeDelta?: (old: unknown, upserted?: unknown[], removed?: string[]) => unknown;
 29→}
 30→
 31→/**
 32→ * Subscribe to a query protocol resource and write snapshots/deltas
 33→ * directly into the React Query cache.
 34→ *
 35→ * On q:snapshot: replaces the entire cache entry via setQueryData.
 36→ * On q:delta: merges upserted items and removes removed items (for list resources).
 37→ *
 38→ * IMPORTANT: queryKey must be a pure function of (resource, params). The queryKey
 39→ * is stored in a ref and not included in the subscription effect's dependency
 40→ * array — if queryKey drifts independently from params, the snapshot would write
 41→ * to the wrong cache entry.
 42→ */
 43→export function useQuerySubscription(
 44→  resource: QueryResource,
 45→  options: UseQuerySubscriptionOptions
 46→): void {
 47→  const { queryKey, params, enabled = true, mergeDelta } = options;
 48→  const queryClient = useQueryClient();
 49→
 50→  // Track WS connection state so the subscription effect re-runs when
 51→  // the connection comes up. Without this, hooks that mount before WS
 52→  // connects would return early and never subscribe (staleTime: Infinity
 53→  // means the HTTP fallback data would never refresh).
 54→  const [wsConnected, setWsConnected] = useState(isConnected());
 55→  useEffect(() => {
 56→    return onConnectionChange(setWsConnected);
 57→  }, []);
 58→
 59→  // Stable string key for params so effect doesn't re-run on referential changes
 60→  const stableParamsKey = useMemo(() => (params ? JSON.stringify(params) : ""), [params]);
 61→
 62→  // Use refs for callbacks to avoid re-subscribing on every render
 63→  const queryClientRef = useRef(queryClient);
 64→  queryClientRef.current = queryClient;
 65→
 66→  const queryKeyRef = useRef(queryKey);
 67→  queryKeyRef.current = queryKey;
 68→
 69→  const mergeDeltaRef = useRef(mergeDelta);
 70→  mergeDeltaRef.current = mergeDelta;
 71→
 72→  useEffect(() => {
 73→    if (!enabled || !wsConnected) return;
 74→
 75→    const unsubscribe = subscribe(
 76→      resource,
 77→      params,
 78→      // onSnapshot: replace entire cache entry
 79→      (data) => {
 80→        queryClientRef.current.setQueryData(queryKeyRef.current, data);
 81→      },
 82→      // onDelta: merge incremental updates (for list resources like messages)
 83→      (upserted, removed) => {
 84→        if (!upserted && !removed) return;
 85→
 86→        queryClientRef.current.setQueryData(queryKeyRef.current, (old: unknown) => {
 87→          // Custom merge strategy (e.g., PaginatedMessages for message cache)
 88→          if (mergeDeltaRef.current) {
 89→            return mergeDeltaRef.current(old, upserted, removed);
 90→          }
 91→
 92→          // Default: flat array merge
 93→          if (!Array.isArray(old)) return old;
 94→
 95→          let result = [...old];
 96→
 97→          // Remove items by ID
 98→          if (removed && removed.length > 0) {
 99→            const removeSet = new Set(removed);
100→            result = result.filter(
101→              (item: unknown) =>
102→                !(
103→                  typeof item === "object" &&
104→                  item !== null &&
105→                  "id" in item &&
106→                  removeSet.has((item as { id: string }).id)
107→                )
108→            );
109→          }
110→
111→          // Upsert items (update existing or append new)
112→          if (upserted && upserted.length > 0) {
113→            for (const item of upserted) {
114→              if (typeof item !== "object" || item === null || !("id" in item)) {
115→                result.push(item);
116→                continue;
117→              }
118→              const itemId = (item as { id: string }).id;
119→              const idx = result.findIndex(
120→                (existing: unknown) =>
121→                  typeof existing === "object" &&
122→                  existing !== null &&
123→                  "id" in existing &&
124→                  (existing as { id: string }).id === itemId
125→              );
126→              if (idx >= 0) {
127→                result[idx] = item;
128→              } else {
129→                result.push(item);
130→              }
131→            }
132→          }
133→
134→          return result;
135→        });
136→      }
137→    );
138→
139→    return unsubscribe;
140→    // eslint-disable-next-line react-hooks/exhaustive-deps
141→  }, [resource, enabled, stableParamsKey, wsConnected]);
142→}
143→

  1→// backend/src/services/query-engine.ts
  2→// Query engine — handles q:* protocol frames for typed reactive queries.
  3→// Module singleton: subscription state + dispatch logic.
  4→// Works for both local WS and relay-tunneled connections via WsSendable.
  5→//
  6→// Subscription model: ID-keyed. Client assigns IDs ("sub_1", "sub_2") and
  7→// server echoes them back on q:snapshot/q:delta so the client can route
  8→// to the correct callback.
  9→
 10→import { match } from "ts-pattern";
 11→import { getDatabase } from "../lib/database";
 12→import {
 13→  getDashboardWorkspaces,
 14→  getStats,
 15→  getSessionsByWorkspaceId,
 16→  getSessionById,
 17→  getMessages,
 18→  hasOlderMessages,
 19→  hasNewerMessages,
 20→  getWorkspaceRaw,
 21→  getMaxMessageSeq,
 22→  getMessagesDelta,
 23→  resetStatsCache,
 24→  getWorkspacesByRepo,
 25→  getWorkspacesBySessionIds,
 26→  getAllRepositorySummaries,
 27→  getSessionRaw,
 28→} from "../db";
 29→import { computeWorkspacePath } from "../middleware/workspace-loader";
 30→import { writeUserMessage } from "./message-writer";
 31→import { getConnection } from "./ws.service";
 32→import {
 33→  QUERY_RESOURCES,
 34→  MUTATION_NAMES,
 35→  COMMAND_NAMES,
 36→  type MutationName,
 37→  type CommandName,
 38→  type QueryResource,
 39→  type QServerFrame,
 40→} from "../../../shared/types/query-protocol";
 41→
 42→// ---- Subscription State ----
 43→
 44→type QueryParams = Record<string, unknown>;
 45→
 46→interface ResourceFrameInput {
 47→  id: string;
 48→  resource: string;
 49→  params: QueryParams;
 50→}
 51→
 52→interface UnsubscribeFrameInput {
 53→  id: string;
 54→}
 55→
 56→interface MutateFrameInput {
 57→  id: string;
 58→  action: string;
 59→  params: QueryParams;
 60→}
 61→
 62→interface CommandFrameInput {
 63→  id: string;
 64→  command: string;
 65→  params: QueryParams;
 66→}
 67→
 68→interface Sub {
 69→  id: string;
 70→  resource: QueryResource;
 71→  params: QueryParams;
 72→}
 73→
 74→/** Per-connection active subscriptions, keyed by client-assigned sub ID. */
 75→const subs = new Map<string, Map<string, Sub>>();
 76→
 77→/** For messages: track last seen seq per subscription for delta push.
 78→ *  Key: `${connectionId}:${subId}` → lastSeq */
 79→const messageCursors = new Map<string, number>();
 80→
 81→// ---- Public API ----
 82→
 83→/**
 84→ * Handle an incoming q:* frame from an authenticated connection.
 85→ * Registered as onQueryFrame in ws.service protocol handlers.
 86→ */
 87→export function handleFrame(connectionId: string, msg: QueryParams): void {
 88→  const type = typeof msg.type === "string" ? msg.type : "unknown";
 89→
 90→  try {
 91→    match(type)
 92→      .with("q:request", () => {
 93→        handleRequest(connectionId, parseResourceFrame(msg));
 94→      })
 95→      .with("q:subscribe", () => {
 96→        handleSubscribe(connectionId, parseResourceFrame(msg));
 97→      })
 98→      .with("q:unsubscribe", () => {
 99→        handleUnsubscribe(connectionId, parseUnsubscribeFrame(msg));
100→      })
101→      .with("q:mutate", () => {
102→        handleMutate(connectionId, parseMutateFrame(msg));
103→      })
104→      .with("q:command", () => {
105→        handleCommand(connectionId, parseCommandFrame(msg));
106→      })
107→      .otherwise(() => {
108→        sendFrame(connectionId, {
109→          type: "q:error",
110→          id: getFrameId(msg),
111→          code: "UNKNOWN_FRAME",
112→          message: `Unknown query frame type: ${type}`,
113→        });
114→      });
115→  } catch (err) {
116→    sendFrame(connectionId, {
117→      type: "q:error",
118→      id: getFrameId(msg),
119→      code: "INVALID_FRAME",
120→      message: err instanceof Error ? err.message : "Invalid query frame",
121→    });
122→  }
123→}
124→
125→/** Remove all subscriptions for a connection (cleanup on disconnect). */
126→export function removeSubs(connectionId: string): void {
127→  const connSubs = subs.get(connectionId);
128→  if (connSubs) {
129→    for (const [subId, sub] of connSubs) {
130→      if (sub.resource === "messages") {
131→        messageCursors.delete(`${connectionId}:${subId}`);
132→      }
133→    }
134→    subs.delete(connectionId);
135→  }
136→}
137→
138→/** Optional context for targeted invalidation (e.g., which sessions changed). */
139→interface InvalidateContext {
140→  sessionIds?: string[];
141→}
142→
143→/**
144→ * Push-first invalidation: re-run queries for active subscribers and push
145→ * fresh snapshots or deltas.
146→ *
147→ * Messages use q:delta (cursor-based) instead of full snapshots.
148→ * When `ctx.sessionIds` is provided, workspace subscribers receive a targeted
149→ * q:delta (only the changed workspaces) instead of a full q:snapshot.
150→ */
151→export function invalidate(resources: QueryResource[], ctx?: InvalidateContext): void {
152→  if (resources.includes("stats")) {
153→    resetStatsCache();
154→  }
155→
156→  // Phase 1: Push fresh data to active subscribers
157→  for (const [connectionId, connSubs] of subs) {
158→    if (!getConnection(connectionId)) {
159→      removeSubs(connectionId);
160→      continue;
161→    }
162→
163→    for (const [subId, sub] of connSubs) {
164→      if (!resources.includes(sub.resource)) continue;
165→
166→      if (sub.resource === "messages") {
167→        // Messages: push delta (new messages since last cursor)
168→        pushMessageDelta(connectionId, subId, sub.params);
169→      } else if (sub.resource === "workspaces" && ctx?.sessionIds?.length) {
170→        // Workspaces with session context: try targeted delta
171→        try {
172→          const db = getDatabase();
173→          const changedWorkspaces = getWorkspacesBySessionIds(db, ctx.sessionIds);
174→          if (changedWorkspaces.length > 0) {
175→            const withPaths = changedWorkspaces.map(ws => ({
176→              ...ws,
177→              workspace_path: computeWorkspacePath(ws),
178→            }));
179→            sendFrame(connectionId, {
180→              type: "q:delta",
181→              id: subId,
182→              upserted: withPaths,
183→            });
184→          } else {
185→            // Session IDs didn't match any workspaces — fall back to full snapshot
186→            const data = runQuery(sub.resource, sub.params);
187→            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
188→          }
189→        } catch (err) {
190→          // Delta lookup failed — fall back to full snapshot
191→          console.error(`[QueryEngine] Workspace delta failed, falling back to snapshot:`, err);
192→          try {
193→            const data = runQuery(sub.resource, sub.params);
194→            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
195→          } catch (snapErr) {
196→            console.error(`[QueryEngine] Snapshot fallback also failed:`, snapErr);
197→          }
198→        }
199→      } else if (sub.resource === "session" && ctx?.sessionIds?.length) {
200→        // Session with context: only push if this subscription's session is in the changed set
201→        const subscribedSessionId = readStringParam(sub.params, "sessionId");
202→        if (subscribedSessionId && ctx.sessionIds.includes(subscribedSessionId)) {
203→          try {
204→            const data = runQuery(sub.resource, sub.params);
205→            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
206→          } catch (err) {
207→            console.error(`[QueryEngine] Session snapshot push failed:`, err);
208→          }
209→        }
210→        // If session not in changed set, skip the push
211→      } else {
212→        // Other resources: push full snapshot
213→        try {
214→          const data = runQuery(sub.resource, sub.params);
215→          sendFrame(connectionId, {
216→            type: "q:snapshot",
217→            id: subId,
218→            data,
219→          });
220→        } catch (err) {
221→          console.error(`[QueryEngine] Snapshot push failed for ${sub.resource}:`, err);
222→        }
223→      }
224→    }
225→  }
226→
227→}
228→
229→// ---- Frame Handlers ----
230→
231→function handleRequest(connectionId: string, msg: ResourceFrameInput): void {
232→  const { id, resource, params } = msg;
233→
234→  try {
235→    const typedResource = toQueryResource(resource);
236→    const data = runQuery(typedResource, params);
237→    sendFrame(connectionId, { type: "q:response", id, data });
238→  } catch (err) {
239→    sendFrame(connectionId, {
240→      type: "q:error",
241→      id,
242→      code: "QUERY_ERROR",
243→      message: err instanceof Error ? err.message : "Query failed",
244→    });
245→  }
246→}
247→
248→function handleSubscribe(connectionId: string, msg: ResourceFrameInput): void {
249→  const { id, resource, params } = msg;
250→
251→  // Validate resource upfront — fail fast before running query
252→  const typedResource = toQueryResource(resource);
253→
254→  // Send initial snapshot — only register subscription if query succeeds
255→  // (avoids zombie subscriptions when runQuery throws on invalid params)
256→  try {
257→    const data = runQuery(typedResource, params);
258→
259→    // Get or create subscription map for this connection
260→    let connSubs = subs.get(connectionId);
261→    if (!connSubs) {
262→      connSubs = new Map();
263→      subs.set(connectionId, connSubs);
264→    }
265→
266→    // Store subscription by client-assigned ID (replaces if same ID reused on reconnect)
267→    connSubs.set(id, { id, resource: typedResource, params });
268→
269→    // For messages: initialize cursor to current max seq
270→    if (typedResource === "messages") {
271→      const sessionId = readStringParam(params, "sessionId");
272→      const cursorKey = `${connectionId}:${id}`;
273→      if (sessionId) {
274→        try {
275→          const db = getDatabase();
276→          messageCursors.set(cursorKey, getMaxMessageSeq(db, sessionId));
277→        } catch {
278→          messageCursors.set(cursorKey, 0);
279→        }
280→      }
281→    }
282→
283→    sendFrame(connectionId, { type: "q:snapshot", id, data });
284→  } catch (err) {
285→    sendFrame(connectionId, {
286→      type: "q:error",
287→      id,
288→      code: "SUBSCRIBE_ERROR",
289→      message: err instanceof Error ? err.message : "Subscribe failed",
290→    });
291→  }
292→}
293→
294→function handleUnsubscribe(connectionId: string, msg: UnsubscribeFrameInput): void {
295→  const { id } = msg;
296→
297→  const connSubs = subs.get(connectionId);
298→  if (!connSubs) return;
299→
300→  const sub = connSubs.get(id);
301→  if (sub) {
302→    // Clean up message cursor
303→    if (sub.resource === "messages") {
304→      messageCursors.delete(`${connectionId}:${id}`);
305→    }
306→    connSubs.delete(id);
307→    if (connSubs.size === 0) subs.delete(connectionId);
308→  }
309→}
310→
311→function handleMutate(connectionId: string, msg: MutateFrameInput): void {
312→  const { id, action, params } = msg;
313→
314→  try {
315→    const result = runMutation(action, params);
316→    sendFrame(connectionId, {
317→      type: "q:mutate_result",
318→      id,
319→      success: true,
320→      data: result,
321→    });
322→  } catch (err) {
323→    sendFrame(connectionId, {
324→      type: "q:mutate_result",
325→      id,
326→      success: false,
327→      error: err instanceof Error ? err.message : "Mutation failed",
328→    });
329→  }
330→}
331→
332→function handleCommand(connectionId: string, msg: CommandFrameInput): void {
333→  const { id, command, params } = msg;
334→
335→  try {
336→    const result = runCommand(command, params);
337→    sendFrame(connectionId, {
338→      type: "q:command_ack",
339→      id,
340→      accepted: true,
341→      ...result,
342→    } satisfies QServerFrame);
343→  } catch (err) {
344→    sendFrame(connectionId, {
345→      type: "q:command_ack",
346→      id,
347→      accepted: false,
348→      error: err instanceof Error ? err.message : "Command failed",
349→    } satisfies QServerFrame);
350→  }
351→}
352→
353→// ---- Command Dispatch ----
354→
355→function runCommand(command: string, params: QueryParams): { commandId?: string } {
356→  const typedCommand = toCommandName(command);
357→
358→  return match(typedCommand)
359→    .with("sendMessage", () => {
360→      const sessionId = readStringParam(params, "sessionId");
361→      const content = readStringParam(params, "content");
362→      const model = readStringParam(params, "model");
363→      if (!sessionId || !content) {
364→        throw new Error("sendMessage requires sessionId and content");
365→      }
366→
367→      const result = writeUserMessage(sessionId, content, model);
368→      if (!result.success) throw new Error(result.error);
369→      invalidate(["workspaces", "sessions", "session", "messages", "stats"], { sessionIds: [sessionId] });
370→      return { commandId: result.messageId };
371→    })
372→    .with("stopSession", () => {
373→      const sessionId = readStringParam(params, "sessionId");
374→      if (!sessionId) throw new Error("stopSession requires sessionId");
375→
376→      const db = getDatabase();
377→      const session = getSessionRaw(db, sessionId);
378→      if (!session) throw new Error("Session not found");
379→
380→      db.prepare("UPDATE sessions SET status = 'idle', updated_at = datetime('now') WHERE id = ?").run(sessionId);
381→      invalidate(["workspaces", "sessions", "session", "stats"], { sessionIds: [sessionId] });
382→      return {};
383→    })
384→    .exhaustive();
385→}
386→
387→// ---- Query Dispatch ----
388→
389→function runQuery(resource: QueryResource, params: QueryParams): unknown {
390→  const db = getDatabase();
391→
392→  return match(resource)
393→    .with("workspaces", () => {
394→      // Return RepoGroup[] shape matching GET /workspaces/by-repo
395→      const state = readStringParam(params, "state") ?? "ready,initializing";
396→      const workspaces = getWorkspacesByRepo(db, state);
397→
398→      const grouped: Record<string, { repo_id: string; repo_name: string; sort_order: number; workspaces: unknown[] }> = {};
399→      workspaces.forEach(workspace => {
400→        const repoId = workspace.repository_id || "unknown";
401→        if (!grouped[repoId]) {
402→          grouped[repoId] = {
403→            repo_id: repoId,
404→            repo_name: workspace.repo_name || "Unknown",
405→            sort_order: workspace.repo_sort_order || 999,
406→            workspaces: [],
407→          };
408→        }
409→        grouped[repoId].workspaces.push({ ...workspace, workspace_path: computeWorkspacePath(workspace) });
410→      });
411→
412→      // Backfill repos that have no matching workspaces (e.g. all archived)
413→      const allRepos = getAllRepositorySummaries(db);
414→      for (const repo of allRepos) {
415→        if (!grouped[repo.id]) {
416→          grouped[repo.id] = {
417→            repo_id: repo.id,
418→            repo_name: repo.name,
419→            sort_order: repo.sort_order ?? 999,
420→            workspaces: [],
421→          };
422→        }
423→      }
424→
425→      return Object.values(grouped).sort((a, b) => a.sort_order - b.sort_order);
426→    })
427→    .with("stats", () => getStats(db))
428→    .with("sessions", () => {
429→      const workspaceId = readStringParam(params, "workspaceId");
430→      if (!workspaceId) throw new Error("sessions requires workspaceId param");
431→      return getSessionsByWorkspaceId(db, workspaceId);
432→    })
433→    .with("session", () => {
434→      const sessionId = readStringParam(params, "sessionId");
435→      if (!sessionId) throw new Error("session requires sessionId param");
436→      return getSessionById(db, sessionId);
437→    })
438→    .with("messages", () => {
439→      const sessionId = readStringParam(params, "sessionId");
440→      if (!sessionId) throw new Error("messages requires sessionId param");
441→
442→      const rows = getMessages(db, sessionId, {
443→        limit: readNumberParam(params, "limit") ?? 50,
444→        before: readNumberParam(params, "before"),
445→        after: readNumberParam(params, "after"),
446→      });
447→
448→      const hasOlder = rows.length > 0 ? hasOlderMessages(db, sessionId, rows[0].seq) : false;
449→      const hasNewer = rows.length > 0
450→        ? hasNewerMessages(db, sessionId, rows[rows.length - 1].seq)
451→        : false;
452→
453→      return { messages: rows, has_older: hasOlder, has_newer: hasNewer };
454→    })
455→    .exhaustive();
456→}
457→
458→// ---- Mutation Dispatch ----
459→
460→function runMutation(action: string, params: QueryParams): unknown {
461→  const typedAction = toMutationName(action);
462→
463→  return match(typedAction)
464→    .with("archiveWorkspace", () => {
465→      const db = getDatabase();
466→      const workspaceId = readStringParam(params, "workspaceId");
467→      if (!workspaceId) throw new Error("archiveWorkspace requires workspaceId");
468→
469→      const workspace = getWorkspaceRaw(db, workspaceId);
470→      if (!workspace) throw new Error("Workspace not found");
471→
472→      db.prepare("UPDATE workspaces SET state = 'archived' WHERE id = ?").run(workspaceId);
473→      invalidate(["workspaces", "stats"]);
474→      return { success: true };
475→    })
476→    .with("updateWorkspaceTitle", () => {
477→      const db = getDatabase();
478→      const workspaceId = readStringParam(params, "workspaceId");
479→      const title = readStringParam(params, "title");
480→      if (!workspaceId || title === undefined) {
481→        throw new Error("updateWorkspaceTitle requires workspaceId and title");
482→      }
483→
484→      const workspace = getWorkspaceRaw(db, workspaceId);
485→      if (!workspace) throw new Error("Workspace not found");
486→
487→      db.prepare("UPDATE workspaces SET title = ? WHERE id = ?").run(title, workspaceId);
488→      invalidate(["workspaces"]);
489→      return { success: true };
490→    })
491→    .exhaustive();
492→}
493→
494→// ---- Message Delta Push ----
495→
496→function pushMessageDelta(connectionId: string, subId: string, params: QueryParams): void {
497→  const sessionId = readStringParam(params, "sessionId");
498→  if (!sessionId) return;
499→
500→  const cursorKey = `${connectionId}:${subId}`;
501→  const lastSeq = messageCursors.get(cursorKey) ?? 0;
502→
503→  try {
504→    const db = getDatabase();
505→    const newMessages = getMessagesDelta(db, sessionId, lastSeq);
506→
507→    if (newMessages.length === 0) return;
508→
509→    const maxSeq = newMessages[newMessages.length - 1].seq;
510→    messageCursors.set(cursorKey, maxSeq);
511→
512→    sendFrame(connectionId, {
513→      type: "q:delta",
514→      id: subId,
515→      upserted: newMessages,
516→      cursor: maxSeq,
517→    });
518→  } catch (err) {
519→    console.error(`[QueryEngine] Message delta push failed:`, err);
520→  }
521→}
