208→// ─── Message Queries ─────────────────────────────────────────
209→
210→/**
211→ * Fetch paginated messages for a session.
212→ * Uses seq (per-session monotonic integer) as cursor — no collisions,
213→ * no NULLs, integer comparison. sent_at had 15K+ collisions in production.
214→ */
215→export function getMessages(
216→  db: Database.Database,
217→  sessionId: string,
218→  opts: { limit: number; before?: number; after?: number }
219→): MessageRow[] {
220→  if (opts.before) {
221→    // Load older: fetch N messages before seq, then re-sort ascending
222→    return db.prepare(`
223→      SELECT * FROM (
224→        SELECT * FROM messages
225→        WHERE session_id = ? AND seq < ?
226→        ORDER BY seq DESC
227→        LIMIT ?
228→      ) sub ORDER BY seq ASC
229→    `).all(sessionId, opts.before, opts.limit) as MessageRow[];
230→  }
231→
232→  if (opts.after) {
233→    // Load newer: fetch N messages after seq, already in ascending order
234→    return db.prepare(`
235→      SELECT * FROM messages
236→      WHERE session_id = ? AND seq > ?
237→      ORDER BY seq ASC
238→      LIMIT ?
239→    `).all(sessionId, opts.after, opts.limit) as MessageRow[];
240→  }
241→
242→  // Default: load latest N messages (DESC then re-wrap ASC)
243→  return db.prepare(`
244→    SELECT * FROM (
245→      SELECT * FROM messages
246→      WHERE session_id = ?
247→      ORDER BY seq DESC
248→      LIMIT ?
249→    ) sub ORDER BY seq ASC
250→  `).all(sessionId, opts.limit) as MessageRow[];
251→}
