  1→/**
  2→ * Workspace Initialization Pipeline
  3→ *
  4→ * Orchestrates the multi-step process of creating a workspace:
  5→ *   1. git worktree add (fatal — cleanup on failure)
  6→ *   2. Dependency installation via lockfile-detected PM (non-fatal)
  7→ *   3. Post-create hooks: .env / .env.local copy (non-fatal)
  8→ *   4. Git clean: restore tracked files so diff starts at zero (non-fatal)
  9→ *   5. Session creation + state transition to 'ready' (fatal)
 10→ *
 11→ * Each step updates the workspace's `init_stage` column in DB and emits
 12→ * a structured stdout line that Rust parses and relays as a Tauri event:
 13→ *   OPENDEVS_WORKSPACE_PROGRESS:{"workspaceId":"...","step":"...","label":"..."}
 14→ *
 15→ * Design decisions:
 16→ * - Pipeline runs in-process (async), not as spawned child — proper try/catch
 17→ * - Non-fatal steps (deps, hooks) log warnings but don't block workspace creation
 18→ * - Reverse-order cleanup on fatal failure: rm dir → prune worktree → delete branch
 19→ * - Structured init pipeline with deps install
 20→ */
 21→
 22→import fs from 'fs';
 23→import path from 'path';
 24→import { execFile } from 'child_process';
 25→import { promisify } from 'util';
 26→import { uuidv7 } from '@shared/lib/uuid';
 27→import { getDatabase } from '../lib/database';
 28→import { invalidate } from './query-engine';
 29→
 30→const execFileAsync = promisify(execFile);
 31→
 32→/** Check if an error is a retryable SQLite concurrency error (BUSY / locked). */
 33→export function isRetryableDbError(err: unknown): boolean {
 34→  if (!(err instanceof Error)) return false;
 35→  const msg = err.message.toLowerCase();
 36→  return msg.includes('sqlite_busy') || msg.includes('database is locked') || msg.includes('database is busy');
 37→}
