 76→// ─── Package Manager Detection ──────────────────────────────────
 77→
 78→interface PackageManager {
 79→  command: string;
 80→  args: string[];
 81→}
 82→
 83→/**
 84→ * Detect the package manager from lockfile presence in the workspace.
 85→ * Returns null if no package.json exists (nothing to install).
 86→ */
 87→export function detectPackageManager(dir: string): PackageManager | null {
 88→  // Check lockfiles in priority order (bun first — project default)
 89→  if (fs.existsSync(path.join(dir, 'bun.lock')) || fs.existsSync(path.join(dir, 'bun.lockb'))) {
 90→    return { command: 'bun', args: ['install', '--frozen-lockfile'] };
 91→  }
 92→  if (fs.existsSync(path.join(dir, 'yarn.lock'))) {
 93→    return { command: 'yarn', args: ['install', '--frozen-lockfile'] };
 94→  }
 95→  if (fs.existsSync(path.join(dir, 'pnpm-lock.yaml'))) {
 96→    return { command: 'pnpm', args: ['install', '--frozen-lockfile'] };
 97→  }
 98→  if (fs.existsSync(path.join(dir, 'package-lock.json'))) {
 99→    return { command: 'npm', args: ['ci'] };
100→  }
101→  // package.json exists but no lockfile — try npm install
102→  if (fs.existsSync(path.join(dir, 'package.json'))) {
103→    return { command: 'npm', args: ['install'] };
104→  }
105→  return null;
106→}
107→
108→// ─── Cleanup ────────────────────────────────────────────────────
109→
110→async function cleanupWorktree(
111→  repoRootPath: string,
112→  workspacePath: string,
113→  branchName: string,
114→): Promise<void> {
115→  // Remove worktree directory
116→  try {
117→    if (fs.existsSync(workspacePath)) {
118→      fs.rmSync(workspacePath, { recursive: true, force: true });
119→    }
120→  } catch (e) {
121→    console.warn('[WORKSPACE] Failed to remove worktree directory:', e);
122→  }
123→
124→  // Prune git worktree references
125→  try {
126→    await execFileAsync('git', ['worktree', 'prune'], {
127→      cwd: repoRootPath,
128→      timeout: 5_000,
129→    });
130→  } catch (e) {
131→    console.warn('[WORKSPACE] Failed to prune worktrees:', e);
132→  }
133→
134→  // Delete the orphaned branch
135→  try {
136→    await execFileAsync('git', ['branch', '-D', branchName], {
137→      cwd: repoRootPath,
138→      timeout: 5_000,
139→    });
140→  } catch {
141→    // Branch may not have been created — that's fine
142→  }
143→}
144→
145→// ─── Pipeline Stages ────────────────────────────────────────────
146→
147→const STAGES: InitStage[] = [
148→  {
149→    name: 'worktree',
150→    label: 'Creating worktree...',
151→    fatal: true,
152→    async run(ctx) {
153→      await execFileAsync('git', [
154→        'worktree', 'add', '-b', ctx.branchName, ctx.workspacePath, ctx.worktreeBase,
155→      ], { cwd: ctx.repoRootPath, timeout: 30_000 });
156→    },
157→    async cleanup(ctx) {
158→      await cleanupWorktree(ctx.repoRootPath, ctx.workspacePath, ctx.branchName);
159→    },
160→  },
161→  {
162→    name: 'dependencies',
163→    label: 'Installing dependencies...',
164→    fatal: false,
165→    async run(ctx) {
166→      const pm = detectPackageManager(ctx.workspacePath);
167→      if (!pm) {
168→        console.log('[WORKSPACE] No package.json found, skipping dependency install');
169→        return;
170→      }
171→      console.log(`[WORKSPACE] Installing dependencies with ${pm.command}...`);
172→      await execFileAsync(pm.command, pm.args, {
173→        cwd: ctx.workspacePath,
174→        timeout: 120_000, // 2 min max for large installs
175→        env: { ...process.env, CI: '1' }, // Suppress interactive prompts
176→      });
177→    },
178→  },
179→  {
180→    name: 'hooks',
181→    label: 'Setting up environment...',
182→    fatal: false,
183→    async run(ctx) {
184→      // Copy .env from repo root if it exists and worktree doesn't have one
185→      const envFiles = ['.env', '.env.local'];
186→      for (const envFile of envFiles) {
187→        const src = path.join(ctx.repoRootPath, envFile);
188→        const dst = path.join(ctx.workspacePath, envFile);
189→        if (fs.existsSync(src) && !fs.existsSync(dst)) {
190→          try {
191→            fs.copyFileSync(src, dst);
192→            console.log(`[WORKSPACE] Copied ${envFile} to worktree`);
193→          } catch (e) {
194→            console.warn(`[WORKSPACE] Failed to copy ${envFile}:`, e);
195→          }
196→        }
197→      }
198→    },
199→  },
200→  {
201→    name: 'git-clean',
202→    label: 'Verifying workspace...',
203→    fatal: false,
204→    async run(ctx) {
205→      // After deps install and .env copy, the working directory may have
206→      // tracked-file modifications (e.g., lockfile normalization by the
207→      // package manager, generated build cache files). Reset tracked files
208→      // to match the index so the diff pipeline sees zero changes on a
209→      // fresh workspace branched from origin/main.
210→      await execFileAsync('git', ['checkout', '--', '.'], {
211→        cwd: ctx.workspacePath,
212→        timeout: 10_000,
213→      });
214→    },
215→  },
216→  {
217→    name: 'session',
218→    label: 'Finalizing...',
219→    fatal: true,
220→    async run(ctx) {
221→      // Retry with exponential backoff to handle SQLITE_BUSY / database-locked
222→      // errors that can occur when the sidecar is concurrently accessing the DB.
223→      const db = getDatabase();
224→      const sessionId = uuidv7();
225→      const maxAttempts = 3;
226→
227→      for (let attempt = 1; attempt <= maxAttempts; attempt++) {
228→        try {
229→          const finalize = db.transaction(() => {
230→            db.prepare(
231→              "INSERT INTO sessions (id, workspace_id, status, updated_at) VALUES (?, ?, 'idle', datetime('now'))"
232→            ).run(sessionId, ctx.workspaceId);
233→            db.prepare(
234→              "UPDATE workspaces SET state = 'ready', current_session_id = ?, init_stage = 'done' WHERE id = ?"
235→            ).run(sessionId, ctx.workspaceId);
236→          });
237→          finalize();
238→          return;
239→        } catch (err) {
240→          if (attempt < maxAttempts && isRetryableDbError(err)) {
241→            const delay = Math.pow(2, attempt) * 100; // 200ms, 400ms
242→            console.warn(
243→              `[WORKSPACE] Session creation attempt ${attempt}/${maxAttempts} failed (${(err as Error).message}), retrying in ${delay}ms...`
244→            );
245→            await new Promise((r) => setTimeout(r, delay));
246→          } else {
247→            throw err;
248→          }
249→        }
250→      }
251→    },
252→  },
253→];
254→
255→// ─── Pipeline Runner ────────────────────────────────────────────
256→
257→export async function initializeWorkspace(ctx: InitContext): Promise<void> {
258→  const completed: InitStage[] = [];
259→
260→  for (const stage of STAGES) {
261→    try {
262→      updateInitStage(ctx.workspaceId, stage.name);
263→    } catch (err) {
264→      // SQLITE_BUSY can fire when sidecar holds the DB — log but don't
265→      // abort, otherwise cleanup never runs and worktrees leak.
266→      console.warn('[WORKSPACE] Failed to update init_stage:', err);
267→    }
268→    emitProgress(ctx.workspaceId, stage.name, stage.label);
269→
270→    try {
271→      await stage.run(ctx);
272→      completed.push(stage);
273→    } catch (err) {
274→      console.error(`[WORKSPACE] Stage "${stage.name}" failed:`, err);
275→
276→      if (stage.fatal) {
277→        // Reverse-order cleanup of completed stages
278→        for (const done of [...completed].reverse()) {
279→          if (done.cleanup) {
280→            await done.cleanup(ctx).catch((e) =>
281→              console.warn(`[WORKSPACE] Cleanup for "${done.name}" failed:`, e)
282→            );
283→          }
284→        }
285→
286→        const db = getDatabase();
287→        db.prepare(
288→          "UPDATE workspaces SET state = 'error', init_stage = ?, error_message = ? WHERE id = ?"
289→        ).run(stage.name, (err as Error).message, ctx.workspaceId);
290→
291→        emitProgress(ctx.workspaceId, 'error', `Failed at: ${stage.name}`);
292→
293→        // Workspace transitioned to 'error' — notify connected clients.
294→        invalidate(['workspaces', 'stats']);
295→        return;
296→      }
297→      // Non-fatal: log and continue to next stage
298→      console.warn(`[WORKSPACE] Non-fatal stage "${stage.name}" failed, continuing...`);
299→    }
300→  }
301→
302→  emitProgress(ctx.workspaceId, 'done', 'Ready');
303→
304→  // Workspace transitioned to 'ready' — push to all connected clients.
305→  // Query-protocol subscribers get fresh snapshots + q:invalidate for unmounted caches.
306→  invalidate(['workspaces', 'stats', 'sessions']);
307→}
