152→// ─── Session Queries ─────────────────────────────────────────
153→
154→/** Coerce SQLite INTEGER booleans (0/1) to JS booleans so HTTP and Tauri IPC return the same shape. */
155→function coerceSessionBooleans<T extends SessionRow>(row: T): T {
156→  return { ...row, is_hidden: Boolean(row.is_hidden) };
157→}
158→
159→/**
160→ * Session query — uses denormalized message_count column
161→ * instead of COUNT(m.id) JOIN, eliminating expensive aggregation.
162→ */
163→const SESSION_DETAILS_SELECT = `
164→  SELECT s.*, w.slug, w.state as workspace_state
165→  FROM sessions s
166→  LEFT JOIN workspaces w ON s.id = w.current_session_id
167→`;
168→
169→export function getAllSessions(db: Database.Database): SessionWithDetailsRow[] {
170→  const rows = db.prepare(`
171→    ${SESSION_DETAILS_SELECT}
172→    ORDER BY s.updated_at DESC
173→    LIMIT 50
174→  `).all() as SessionWithDetailsRow[];
175→  return rows.map(coerceSessionBooleans);
176→}
177→
178→export function getSessionById(
179→  db: Database.Database,
180→  id: string
181→): SessionWithDetailsRow | undefined {
182→  const row = db.prepare(`
183→    ${SESSION_DETAILS_SELECT}
184→    WHERE s.id = ?
185→  `).get(id) as SessionWithDetailsRow | undefined;
186→  return row ? coerceSessionBooleans(row) : undefined;
187→}
188→
189→export function getSessionRaw(
190→  db: Database.Database,
191→  id: string
192→): SessionRow | undefined {
193→  const row = db.prepare('SELECT * FROM sessions WHERE id = ?').get(id) as SessionRow | undefined;
194→  return row ? coerceSessionBooleans(row) : undefined;
195→}
