197→/** All sessions for a workspace, ordered by creation time (UUID7 is chronological). */
198→export function getSessionsByWorkspaceId(
199→  db: Database.Database,
200→  workspaceId: string
201→): SessionRow[] {
202→  const rows = db.prepare(
203→    'SELECT * FROM sessions WHERE workspace_id = ? ORDER BY id ASC'
204→  ).all(workspaceId) as SessionRow[];
205→  return rows.map(coerceSessionBooleans);
206→}
