276→): string | null {
277→  const row = db.prepare(`
278→    SELECT agent_message_id FROM messages
279→    WHERE session_id = ? AND role = 'assistant' AND agent_message_id IS NOT NULL
280→    ORDER BY id DESC LIMIT 1
281→  `).get(sessionId) as { agent_message_id: string } | undefined;
