292→/** Get the highest seq for a session (cursor initialization for real-time streaming). */
293→export function getMaxMessageSeq(db: Database.Database, sessionId: string): number {
294→  const row = db.prepare(
295→    "SELECT COALESCE(MAX(seq), 0) as max_seq FROM messages WHERE session_id = ?"
296→  ).get(sessionId) as { max_seq: number } | undefined;
