300→/** Fetch all messages after a given seq (delta push for real-time streaming). */
301→export function getMessagesDelta(
302→  db: Database.Database,
303→  sessionId: string,
304→  afterSeq: number
305→): MessageRow[] {
306→  return db.prepare(
307→    "SELECT * FROM messages WHERE session_id = ? AND seq > ? ORDER BY seq ASC"
308→  ).all(sessionId, afterSeq) as MessageRow[];
309→}
