311→// ─── Repository Queries ─────────────────────────────────────
312→
313→export function getAllRepositories(db: Database.Database): RepositoryWithCountsRow[] {
314→  return db.prepare(`
315→    SELECT r.*,
316→           COUNT(CASE WHEN w.state = 'ready' THEN 1 END) as ready_count,
317→           COUNT(CASE WHEN w.state = 'archived' THEN 1 END) as archived_count,
318→           COUNT(w.id) as total_count
319→    FROM repositories r
320→    LEFT JOIN workspaces w ON w.repository_id = r.id
321→    GROUP BY r.id
322→    ORDER BY r.sort_order, r.name
323→  `).all() as RepositoryWithCountsRow[];
324→}
