326→/** Lightweight repo list for backfilling empty groups in by-repo queries. */
327→export function getAllRepositorySummaries(db: Database.Database): { id: string; name: string; sort_order: number }[] {
328→  return db.prepare(
329→    'SELECT id, name, sort_order FROM repositories ORDER BY sort_order, name'
330→  ).all() as { id: string; name: string; sort_order: number }[];
331→}
