333→export function getRepositoryById(
334→  db: Database.Database,
335→  id: string
336→): RepositoryRow | undefined {
337→  return db.prepare('SELECT * FROM repositories WHERE id = ?').get(id) as RepositoryRow | undefined;
338→}
