340→export function getRepositoryByRootPath(
341→  db: Database.Database,
342→  rootPath: string
343→): RepositoryRow | undefined {
344→  return db.prepare('SELECT * FROM repositories WHERE root_path = ?').get(rootPath) as RepositoryRow | undefined;
345→}
