352→// ─── Stats Queries ───────────────────────────────────────────
353→
354→let cachedStats: StatsRow | null = null;
355→let cachedAt = 0;
356→const STATS_TTL_MS = 5_000;
357→
358→export function getStats(db: Database.Database): StatsRow {
359→  const now = Date.now();
360→  if (cachedStats && now - cachedAt < STATS_TTL_MS) return cachedStats;
361→  cachedStats = db.prepare(`
362→    SELECT
363→      (SELECT COUNT(*) FROM workspaces) as workspaces,
364→      (SELECT COUNT(*) FROM workspaces WHERE state = 'ready') as workspaces_ready,
365→      (SELECT COUNT(*) FROM workspaces WHERE state = 'archived') as workspaces_archived,
366→      (SELECT COUNT(*) FROM repositories) as repositories,
367→      (SELECT COUNT(*) FROM sessions) as sessions,
368→      (SELECT COUNT(*) FROM sessions WHERE status = 'idle') as sessions_idle,
369→      (SELECT COUNT(*) FROM sessions WHERE status = 'working') as sessions_working,
370→      (SELECT COUNT(*) FROM messages) as messages
371→  `).get() as StatsRow;
372→  cachedAt = now;
373→  return cachedStats;
374→}
375→
376→/** Reset the in-memory stats cache (for testing). */
377→export function resetStatsCache(): void {
378→  cachedStats = null;
379→  cachedAt = 0;
380→}
