107→        // to avoid leaking the old stream and stale response channel.
108→        {
109→            let has_existing = self.stream.lock().unwrap().is_some();
110→            if has_existing {
111→                println!("[SOCKET] Disconnecting from previous socket before connecting to new path");
112→                let _ = self.disconnect();
113→            }
114→        }
115→
116→        match UnixStream::connect(&path) {
117→            Ok(stream) => {
118→                *self.stream.lock().unwrap() = Some(stream);
119→                *self.socket_path.lock().unwrap() = Some(path);
120→                println!("[SOCKET] Connected to {}", socket_path);
121→                Ok(())
122→            }
123→            Err(e) => Err(format!("Failed to connect to socket: {}", e)),
124→        }
125→    }
126→
127→    /**
128→     * Send NDJSON message to sidecar
129→     *
130→     * @param message - JSON message to send
131→     */
132→    pub fn send(&self, message: String) -> Result<(), String> {
133→        let mut stream_lock = self.stream.lock().unwrap();
134→
135→        match stream_lock.as_mut() {
136→            Some(stream) => {
137→                // NDJSON format: JSON + newline
138→                let ndjson = format!("{}\n", message);
139→                stream
140→                    .write_all(ndjson.as_bytes())
141→                    .map_err(|e| format!("Failed to send message: {}", e))?;
142→                stream
143→                    .flush()
144→                    .map_err(|e| format!("Failed to flush: {}", e))?;
145→                Ok(())
146→            }
147→            None => Err("Not connected to socket".to_string()),
148→        }
149→    }
150→
151→    /**
152→     * Receive a JSON-RPC response from sidecar
153→     *
154→     * Instead of reading from the socket directly (which would race with the
155→     * event listener thread), this reads from the mpsc response channel that
156→     * the event listener populates with JSON-RPC response messages (those with
157→     * an "id" field).
158→     *
159→     * Uses a 30-second timeout to avoid hanging forever if the sidecar dies.
160→     */
161→    pub fn receive(&self) -> Result<String, String> {
162→        let rx_lock = self.response_rx.lock().unwrap();
163→
164→        match rx_lock.as_ref() {
165→            Some(rx) => {
166→                // Use recv_timeout to avoid blocking forever if sidecar dies
167→                // or the connection is dropped while we're waiting.
168→                rx.recv_timeout(Duration::from_secs(30))
169→                    .map_err(|e| match e {
170→                        mpsc::RecvTimeoutError::Timeout => {
171→                            "Timed out waiting for response from sidecar (30s)".to_string()
172→                        }
173→                        mpsc::RecvTimeoutError::Disconnected => {
174→                            "Response channel disconnected (event listener stopped)".to_string()
175→                        }
176→                    })
177→            }
178→            None => Err("Not connected to socket (no response channel)".to_string()),
179→        }
180→    }
181→
182→    /**
183→     * Start listening for broadcast events from sidecar-v2
184→     * Runs in background thread, routing JSON-RPC responses to receive()
185→     *
186→     * ALL socket reads are funneled through this single thread to prevent
187→     * data corruption from concurrent BufReaders on the same fd.
188→     *
189→     * Parses JSON-RPC 2.0 messages from sidecar-v2:
190→     * - Notifications (no "id"): logged but no longer emitted as Tauri events
191→     *   (session data flows via backend WS query protocol q:snapshot/q:delta)
192→     * - Responses (has "id"): dispatched to mpsc channel for receive()
193→     */
194→    pub fn start_event_listener(&self) {
195→        // Create the mpsc channel for routing JSON-RPC responses to receive()
196→        let (response_tx, response_rx) = mpsc::channel::<String>();
197→        *self.response_rx.lock().unwrap() = Some(response_rx);
198→
199→        let stream = Arc::clone(&self.stream);
200→        let app_handle = Arc::clone(&self.app_handle);
201→
202→        thread::spawn(move || {
203→            println!("[SOCKET] Event listener started (JSON-RPC 2.0 mode)");
204→
205→            loop {
206→                // Check if we have a connection
207→                let socket_opt = {
208→                    let stream_guard = stream.lock().unwrap();
209→                    stream_guard.as_ref().and_then(|s| s.try_clone().ok())
210→                };
211→
212→                if let Some(socket) = socket_opt {
213→                    let reader = BufReader::new(&socket);
214→
215→                    for line in reader.lines() {
216→                        match line {
217→                            Ok(line) => {
218→                                // Try to parse as JSON-RPC 2.0 message
219→                                if let Ok(rpc_msg) = serde_json::from_str::<Value>(&line) {
220→                                    let is_jsonrpc = rpc_msg.get("jsonrpc")
221→                                        .and_then(|v| v.as_str()) == Some("2.0");
222→
223→                                    if !is_jsonrpc {
224→                                        continue;
225→                                    }
226→
227→                                    // Dispatch based on message shape:
228→                                    // 1. Has "method" + "id" = sidecar→frontend REQUEST → emit Tauri event
229→                                    // 2. Has "id" but no "method" = response to frontend request → mpsc
230→                                    // 3. Has "method" but no "id" = notification → log and ignore (handled by WS)
231→                                    let has_method = rpc_msg.get("method").and_then(|v| v.as_str()).is_some();
232→                                    let has_id = rpc_msg.get("id").is_some();
233→
234→                                    if has_method && has_id {
235→                                        // Sidecar → Frontend REQUEST (bidirectional RPC)
236→                                        // The sidecar is requesting the frontend to do something
237→                                        // (e.g., eval JS in browser, ask user a question).
238→                                        // Emit as "sidecar:request" with full JSON-RPC envelope.
239→                                        let method = rpc_msg.get("method").and_then(|v| v.as_str()).unwrap_or("unknown");
240→                                        println!("[SOCKET] Sidecar request: {} (id={})", method,
241→                                            rpc_msg.get("id").map(|v| v.to_string()).unwrap_or_default());
242→
243→                                        if let Some(handle) = app_handle.lock().unwrap().as_ref() {
244→                                            let payload = serde_json::json!({
245→                                                "id": rpc_msg.get("id"),
246→                                                "method": method,
247→                                                "params": rpc_msg.get("params").cloned().unwrap_or(Value::Null),
248→                                            });
249→                                            if let Err(e) = handle.emit("sidecar:request", payload) {
250→                                                eprintln!("[SOCKET] Failed to emit sidecar request: {}", e);
251→                                            }
252→                                        }
253→                                    } else if has_id {
254→                                        // Response to frontend-initiated request → route to receive()
255→                                        let _ = response_tx.send(line);
256→                                    } else if has_method {
257→                                        // Notification — log and ignore (handled by WS query protocol)
258→                                        let method = rpc_msg.get("method")
259→                                            .and_then(|v| v.as_str())
260→                                            .unwrap_or("unknown");
261→
262→                                        let params = rpc_msg.get("params").cloned()
263→                                            .unwrap_or(Value::Null);
264→
265→                                        // Session notifications (message, queryError, statusChanged,
266→                                        // enterPlanModeNotification) are now handled by the backend
267→                                        // query engine via WS q:snapshot/q:delta pushes. No Tauri
268→                                        // event mapping needed — the frontend reads from React Query
269→                                        // cache populated by the WS subscription.
270→                                        println!("[SOCKET] Ignoring RPC notification: {} (handled by WS query protocol)", method);
271→                                    }
272→                                }
273→                            }
274→                            Err(e) => {
275→                                eprintln!("[SOCKET] Error reading line: {}", e);
276→                                // Clear the stream so we don't spin in a tight loop
277→                                // trying to read from a broken connection
278→                                *stream.lock().unwrap() = None;
279→                                break; // Connection lost, exit loop
280→                            }
281→                        }
282→                    }
283→
284→                    // Wait a bit before checking again
285→                    thread::sleep(Duration::from_millis(100));
286→                } else {
287→                    // No connection - wait longer before retrying to avoid busy-wait
288→                    thread::sleep(Duration::from_secs(1));
289→                }
290→            }
291→        });
292→    }
293→
294→    /**
295→     * Disconnect from socket
296→     */
297→    pub fn disconnect(&self) -> Result<(), String> {
298→        *self.stream.lock().unwrap() = None;
299→        *self.socket_path.lock().unwrap() = None;
300→        // Clear the response channel so receive() returns an error immediately
301→        // instead of blocking on a stale channel.
302→        *self.response_rx.lock().unwrap() = None;
303→        println!("[SOCKET] Disconnected");
304→        Ok(())
305→    }
306→
307→    /**
308→     * Check if connected
309→     */
310→    pub fn is_connected(&self) -> bool {
311→        self.stream.lock().unwrap().is_some()
312→    }
313→}
314→
315→// Tauri commands are defined in commands.rs to keep them organized
316→

